window.RG_DATA["unit:06-particles"]={"id":"06-particles","num":6,"title":"Phần 6: TIỂU TỪ (Части́цы)","vi":"Tiểu từ","ru":"Частицы","icon":"🔧","color":"#06b6d4","sections":[{"id":"06-s001","type":"exercise","title":"Bài 480 (Trang 240)","num":480,"blocks":[{"t":"para","text":"Đề bài: Đọc các câu văn. Xác định sự khác biệt về ý nghĩa của các từ được in đậm (vừa là tiểu từ, vừa là từ loại khác)."},{"t":"para","text":"Giải thích ý nghĩa:","b":1},{"t":"para","text":"Я хочу́, что́бы ты уе́хал сего́дня. (Что́ бы) ему́ уе́хать сего́дня.","b":1},{"t":"vocab","ru":"Что́бы (liên từ)","vi":"Để cho (mục đích/mong muốn).","g":null},{"t":"vocab","ru":"Что́ бы (Đại từ что + tiểu từ бы)","vi":"Giá mà / Tại sao ... không... (Lời khuyên/Mong muốn). Sao nó không đi hôm nay nhỉ?","g":null},{"t":"para","text":"Он взял лист бума́ги и (реши́тельно) написа́л на нём пе́рвое сло́во. Я (реши́тельно) тебя́ не понима́ю, чего́ ты хо́чешь!","b":1},{"t":"vocab","ru":"Реши́тельно (Trạng từ)","vi":"Một cách kiên quyết.","g":null},{"t":"vocab","ru":"Реши́тельно (Tiểu từ nhấn mạnh)","vi":"Hoàn toàn/Tuyệt đối (không hiểu).","g":null},{"t":"para","text":"Иди́те (пря́мо), зате́м поверни́те нале́во. Посмотри́ на него́: (пря́мо) геро́й, и не поду́маешь, что он неда́вно стру́сил.","b":1},{"t":"vocab","ru":"Пря́мо (Trạng từ)","vi":"Thẳng.","g":null},{"t":"vocab","ru":"Пря́мо (Tiểu từ)","vi":"Cứ như là/Đúng là (nhấn mạnh sự so sánh).","g":null},{"t":"para","text":"В э́тих места́х лу́чше отдыха́ть ле́том, а не зимо́й. Чего́ ты ждёшь, (лу́чше) сходи́ и сам всё сде́лай.","b":1},{"t":"vocab","ru":"Лу́чше (Trạng từ so sánh)","vi":"Tốt hơn.","g":null},{"t":"vocab","ru":"Лу́чше (Tiểu từ)","vi":"Thà/Hãy/Tốt hơn là (lời khuyên). Tốt hơn là đi mà tự làm.","g":null},{"t":"para","text":"(Смотри́), како́й интере́сный цвето́к. Мы за́втра тебя́ ждать не бу́дем, (смотри́) не опозда́й.","b":1},{"t":"vocab","ru":"Смотри́ (Động từ)","vi":"Hãy nhìn kìa.","g":null},{"t":"vocab","ru":"Смотри́ (Tiểu từ cảnh báo)","vi":"Coi chừng/Liệu đấy (đừng đến muộn).","g":null},{"t":"para","text":"Знай он об опа́сности, не пошёл бы туда́ оди́н. Его́ руга́ют, а он (знай (себе́)) молчи́т.","b":1},{"t":"vocab","ru":"Знай (Động từ - Thức mệnh lệnh dùng trong câu điều kiện)","vi":"Nếu anh ta biết...","g":null},{"t":"vocab","ru":"Знай себе (Tiểu từ thành ngữ)","vi":"Cứ phớt lờ/Cứ tiếp tục (mặc kệ tác động bên ngoài).","g":null},{"t":"para","text":"Поезжа́й (скоре́е), мы опа́здываем. Он (скоре́е) умрёт, чем согласи́тся с твои́м предложе́нием. (Скоре́е) бы кани́кулы!","b":1},{"t":"vocab","ru":"Скоре́е (Trạng từ so sánh)","vi":"Nhanh hơn.","g":null},{"t":"vocab","ru":"Скоре́е (Tiểu từ/Trạng từ)","vi":"Thà (chết còn hơn).","g":null},{"t":"vocab","ru":"Скоре́е бы (Tiểu từ mong ước)","vi":"Ước gì/Giá mà (kỳ nghỉ đến sớm).","g":null},{"t":"para","text":"Мы подгото́вили что́-то (вро́де) импровизи́рованного конце́рта. Послу́шай, (вро́де) кто́-то звони́т в дверь. Не зна́ю, почему́ он переду́мал, (вро́де (бы)) вчера́ мы обо всём с ним договори́лись.","b":1},{"t":"vocab","ru":"Вро́де (Giới từ)","vi":"Giống như (cái gì đó).","g":null},{"t":"vocab","ru":"Вро́де / Вро́де бы (Tiểu từ nghi vấn/giả định)","vi":"Hình như/Có vẻ như.","g":null},{"t":"para","text":"Не то́лько зимо́й, но (да́же) в гора́х лежи́т снег. Услы́шав э́то, я (да́же) не стал с ним спо́рить.","b":1},{"t":"vocab","ru":"Да́же (Liên từ trong cặp не только... но даже)","vi":"Mà ngay cả.","g":null},{"t":"vocab","ru":"Да́же (Tiểu từ nhấn mạnh)","vi":"Thậm chí/Đến mức.","g":null},{"t":"para","text":"Э́ту зада́чу мо́жно реши́ть о́чень (про́сто). Вы поста́вили меня́ в тупи́к, (про́сто) не зна́ю, что вам сказа́ть.","b":1},{"t":"vocab","ru":"Про́сто (Trạng từ)","vi":"Một cách đơn giản.","g":null},{"t":"vocab","ru":"Про́сто (Tiểu từ)","vi":"Chỉ là/Thật sự là (nhấn mạnh).","g":null},{"t":"para","text":"Так поступа́ть нельзя́. (Так) мы е́дем и́ли нет?","b":1},{"t":"vocab","ru":"Так (Trạng từ)","vi":"Như thế/Theo cách đó.","g":null},{"t":"vocab","ru":"Так (Tiểu từ/Liên từ nối)","vi":"Thế thì/Vậy thì.","g":null},{"t":"para","text":"(Вот) здесь мы и живём, в э́том до́ме. (Вот) ещё но́вости! (Вот) уви́дите, я обяза́тельно добью́сь успе́ха.","b":1},{"t":"vocab","ru":"Вот (Trạng từ chỉ định)","vi":"Chính đây.","g":null},{"t":"vocab","ru":"Вот (Tiểu từ cảm thán)","vi":"Tin mới chưa kìa! (Ngạc nhiên/Mỉa mai).","g":null},{"t":"vocab","ru":"Вот (Tiểu từ nhấn mạnh tương lai)","vi":"Rồi xem/Cứ chờ đấy.","g":null},{"t":"para","text":"Мы приходи́ли, (да) до́ма никого́ не́ было. (Да) я то́лько взгляну́ на него́ оди́н раз. (Вре́мя) бы́ло тяжёлое. Я (бы́ло) пошёл, (да) верну́лся: ключи́ забы́л.","b":1},{"t":"vocab","ru":"Да (Liên từ)","vi":"Nhưng.","g":null},{"t":"vocab","ru":"Да (Tiểu từ)","vi":"Chỉ/Thôi mà (nài nỉ/giảm nhẹ).","g":null},{"t":"vocab","ru":"Бы́ло (Động từ)","vi":"Là.","g":null},{"t":"vocab","ru":"Бы́ло (Tiểu từ)","vi":"Định/Toan (làm gì đó nhưng lại thôi). Tôi toan đi thì lại quay lại.","g":null},{"t":"para","text":"Как я тебе́ сказа́л, (так) ты и де́лай. Услы́шав э́ту но́вость, я (так) и упа́л от сме́ха.","b":1},{"t":"vocab","ru":"Так (Trạng từ)","vi":"Như thế (đối lại với как).","g":null},{"t":"vocab","ru":"Так и (Tiểu từ thành ngữ)","vi":"Suýt thì/Đến mức (ngã ngửa ra).","g":null},{"t":"para","text":"Я (всё) обду́мал, не беспоко́йся. Я (всё) ду́маю, смо́жем мы зако́нчить э́ту рабо́ту во́время и́ли нет.","b":1},{"t":"vocab","ru":"Всё (Đại từ)","vi":"Tất cả.","g":null},{"t":"vocab","ru":"Всё (Tiểu từ)","vi":"Vẫn cứ/Mãi (liên tục suy nghĩ).","g":null},{"t":"para","text":"Dưới đây là phần giải thích chi tiết, dịch thuật và hướng dẫn làm bài tập từ 481 đến 485 trong sách \"Грамматика русского языка в упражнениях и комментариях. Морфология\" (O. I. Glazunova), trang 241-243."},{"t":"para","text":"Tôi sẽ bắt đầu với phần lý thuyết trong các khung ngữ pháp quan trọng cần thiết để làm bài."}]},{"id":"06-s002","type":"grammar","title":"PHẦN NGỮ PHÁP (Trang 240 và 241)","num":null,"blocks":[{"t":"subhead","text":"Lý thuyết về Tiểu từ (Частицы):","b":1},{"t":"para","text":"Tiểu từ (Частица) là hư từ (từ không biến đổi) mang lại cho từ hoặc câu những sắc thái ý nghĩa bổ sung. Trong tiếng Nga phân biệt các loại:"},{"t":"vocab","ru":"Khẳng định (Утвердительные)","vi":"да (vâng/có), действи́тельно (thực sự), конéчно (tất nhiên), тóчно (chính xác).","g":null},{"t":"vocab","ru":"Phủ định (Отрицательные)","vi":"нет (không), не (không), ни (không/chẳng).","g":null},{"t":"vocab","ru":"Nghi vấn (Вопросительные)","vi":"ли (có... không), ль (như ли - thơ ca), рáзве (chẳng lẽ), неужéли (chẳng lẽ/thật ư).","g":null},{"t":"vocab","ru":"Nhấn mạnh (Усилительные)","vi":"же (mà/chính/nhỉ), дáже (thậm chí), тóлько (chỉ), ведь (mà/vì), лишь (chỉ).","g":null},{"t":"vocab","ru":"Cảm thán (Восклицательные)","vi":"что за (cái gì mà/thật là), как (thật là/biết bao), ну и (đúng là/gớm thật).","g":null},{"t":"vocab","ru":"Chỉ định (Указательные)","vi":"вот (đây/kìa), вон (kia), éто (đây là).","g":null},{"t":"vocab","ru":"Xác định, làm rõ (Определительно-уточняющие)","vi":"úменно (chính), тóчно (y hệt/đúng), приблизúтельно (khoảng chừng).","g":null}]},{"id":"06-s003","type":"exercise","title":"BÀI TẬP 481 (Trang 241)","num":481,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền các tiểu từ thích hợp vào chỗ trống theo ý nghĩa. (Dựa vào ngữ cảnh để chọn tiểu từ nhấn mạnh, cảm thán hoặc chỉ định phù hợp)."},{"t":"para","text":"1. Как хóчется отдохнýть! Чтó за (hoặc Ну и) óтпуск!","b":1},{"t":"para","text":"Dịch: Thật muốn nghỉ ngơi biết bao! Kỳ nghỉ kiểu gì thế này! (hoặc: Thật là một kỳ nghỉ!)."},{"t":"example","text":"Giải thích: Как dùng để cảm thán mức độ mong muốn. Что за hoặc Ну и dùng để biểu lộ cảm xúc mạnh (thường là bất mãn hoặc ngạc nhiên) về danh từ đứng sau."},{"t":"para","text":"2. Я бы́ло нáчал éту рабóту, но потóм подýмал, что её мóгут сдéлать другúе.","b":1},{"t":"para","text":"Dịch: Tôi đã định bắt đầu công việc này rồi, nhưng sau đó lại nghĩ rằng người khác có thể làm nó."},{"t":"example","text":"Giải thích: Tiểu từ бы́ло đứng sau động từ thì quá khứ để chỉ hành động đã bắt đầu hoặc định làm nhưng bị ngắt quãng hoặc không có kết quả."},{"t":"para","text":"3. Будь осторóжен! Смотрú, не потеря́й билéт на пóезд!","b":1},{"t":"para","text":"Dịch: Hãy cẩn thận! Coi chừng, đừng để mất vé tàu đấy!"},{"t":"example","text":"Giải thích: Смотрú ở đây đóng vai trò như một tiểu từ cảnh báo, nhắc nhở."},{"t":"para","text":"4. Извинú, что подвёл тебя́, я прóсто не подýмал о том, что ты бýдешь ждать меня́ пóсле рабóты.","b":1},{"t":"para","text":"Dịch: Xin lỗi vì đã làm lỡ việc của bạn, tôi đơn giản là không nghĩ đến việc bạn sẽ đợi tôi sau giờ làm."},{"t":"example","text":"Giải thích: Прóсто (đơn giản là/chẳng qua là) dùng để biện minh hoặc hạn chế lý do."},{"t":"para","text":"5. С кáждой минýтой емý становúлось всё хýже.","b":1},{"t":"para","text":"Dịch: Cứ mỗi phút trôi qua, anh ấy lại càng trở nên tồi tệ hơn."},{"t":"example","text":"Giải thích: Tiểu từ всё đi kèm với tính từ/trạng từ so sánh hơn (всё хýже) biểu thị sự tăng tiến liên tục của trạng thái."},{"t":"para","text":"6. Не знáю, что с ней случúлось, ведь вчерá я её вúдел в universitetе, но мóжет быть, мне éто показа́лось.","b":1},{"t":"para","text":"Dịch: Tôi không biết chuyện gì đã xảy ra với cô ấy, vì hôm qua tôi (rõ ràng) đã thấy cô ấy ở trường đại học, nhưng có lẽ tôi đã nhìn nhầm."},{"t":"example","text":"Giải thích: Ведь dùng để nhắc lại một sự thật hiển nhiên hoặc đưa ra lý do mà người nói tin là đúng."},{"t":"para","text":"7. Сам я бы никогдá тудá не поéхал, да слýчай удóбный подвернýлся: éхали мои́ друзья́ и взя́ли меня́ с собóй.","b":1},{"t":"para","text":"Dịch: Bản thân tôi sẽ chẳng bao giờ đi đến đó, nhưng mà có dịp thuận tiện: bạn bè tôi đi và rủ tôi theo."},{"t":"example","text":"Giải thích: Да ở đầu mệnh đề mang nghĩa nối tiếp, giải thích hoặc đối lập nhẹ (nhưng mà/chẳng qua là)."},{"t":"para","text":"8. Что бы емý ни говорúли, он всё (hoặc так и) молчúт и продолжáет дéлать по-своемý.","b":1},{"t":"para","text":"Dịch: Dù người ta có nói gì với anh ta đi nữa, anh ta vẫn cứ im lặng và tiếp tục làm theo ý mình."},{"t":"example","text":"Giải thích: Всё hoặc так и nhấn mạnh sự tiếp diễn của hành động bất chấp hoàn cảnh."},{"t":"para","text":"9. В éтой ситуáции я прóсто (hoặc дáже) не знáю, что предприня́ть.","b":1},{"t":"para","text":"Dịch: Trong tình huống này, tôi quả thực (thậm chí) không biết phải làm gì."},{"t":"example","text":"Giải thích: Прóсто hoặc дáже dùng để nhấn mạnh sự bất lực hoặc mức độ của việc không biết."},{"t":"para","text":"10. Идéя хорóшая, нáдо бы́ло (hoặc стóило) тебé вчерá сказáть нам о ней, когдá мы обсужда́ли возмóжные решéния.","b":1},{"t":"para","text":"Dịch: Ý tưởng hay đấy, lẽ ra hôm qua bạn phải nói cho chúng tôi biết về nó khi chúng ta thảo luận các giải pháp khả thi."},{"t":"example","text":"Giải thích: Cấu trúc нáдо бы́ло (lẽ ra phải) diễn tả sự tiếc nuối về việc chưa làm trong quá khứ."},{"t":"para","text":"11. Éсли ты встрéтишь их где-нибýдь в гостя́х, ни за что не подýмаешь, что онú терпéть друг дрýга не мóгут: улыбáются, разговáривают... Пря́мо лýчшие друзья́!","b":1},{"t":"para","text":"Dịch: Nếu bạn gặp họ ở đâu đó trong bữa tiệc, bạn sẽ không đời nào nghĩ rằng họ không thể chịu nổi nhau: họ cười nói, trò chuyện... Cứ như là bạn thân nhất ấy!"},{"t":"example","text":"Giải thích: Пря́мо (cứ như là/đúng là) dùng để nhấn mạnh sự so sánh, đôi khi mang sắc thái mỉa mai hoặc ngạc nhiên."},{"t":"para","text":"12. Лýчше поторопúсь, éсли не хóчешь приéхать сáмым послéдним.","b":1},{"t":"para","text":"Dịch: Tốt hơn hết là hãy nhanh lên nếu bạn không muốn đến muộn nhất."},{"t":"example","text":"Giải thích: Лýчше dùng như một lời khuyên, thúc giục."},{"t":"para","text":"13. Вот ещё кандидáт! Никогдá не бýду за негó голосовáть.","b":1},{"t":"para","text":"Dịch: Lại thêm một ứng cử viên nữa này! (hoặc: Ứng cử viên kiểu gì thế này!). Tôi sẽ không bao giờ bầu cho ông ta."},{"t":"example","text":"Giải thích: Вот ещё biểu thị sự phản đối, khinh thường hoặc không chấp nhận."},{"t":"para","text":"14. Говорúл он дóлго, но я так и не пóнял, чегó он хóчет.","b":1},{"t":"para","text":"Dịch: Anh ta nói rất lâu, nhưng tôi rốt cuộc vẫn chẳng hiểu anh ta muốn gì."},{"t":"example","text":"Giải thích: Так и đi với phủ định (не) nghĩa là \"mãi vẫn không\", kết quả cuối cùng vẫn là phủ định."},{"t":"para","text":"15. Ну что ты егó угoвáриваешь?! Да (hoặc Ведь) он не хóчет éхать с тобóй!","b":1},{"t":"para","text":"Dịch: Sao bạn cứ thuyết phục anh ấy mãi thế?! Anh ấy không muốn đi với bạn đâu mà!"},{"t":"example","text":"Giải thích: Да hoặc Ведь dùng để nhấn mạnh sự thật hiển nhiên mà người nghe nên nhận ra."},{"t":"para","text":"16. Вот увид́ите! Éто то, что вам нýжно.","b":1},{"t":"para","text":"Dịch: Các bạn cứ xem (rồi sẽ thấy)! Đây chính là cái các bạn cần."},{"t":"example","text":"Giải thích: Вот trong cụm Вот увидите dùng để khẳng định chắc chắn về một điều sẽ xảy ra hoặc được chứng minh."}]},{"id":"06-s004","type":"exercise","title":"BÀI TẬP 482 (Trang 241)","num":482,"blocks":[{"t":"instruction","text":"Yêu cầu: Trả lời các câu hỏi, sử dụng các tiểu từ cần thiết theo ý nghĩa. (Lưu ý: Đây là bài tập mở, câu trả lời có thể linh hoạt, nhưng phải dùng tiểu từ)."},{"t":"para","text":"1. — Ты устáл?","b":1},{"t":"para","text":"Trả lời: — Едвá на ногáх стою́. (Tôi hầu như không đứng vững nữa / Mệt rã rời)."},{"t":"para","text":"Hoặc: — Ещё бы не устáл! (Sao lại không mệt được chứ! / Mệt chứ sao không)."},{"t":"example","text":"Едвá (hầu như không), Ещё бы (tất nhiên/chắc chắn rồi)."},{"t":"para","text":"2. — Ты не забýл о том, что обещáл нам вчерá сдéлать?","b":1},{"t":"para","text":"Trả lời: — Как раз об этом я и дýмаю. (Tôi chính là đang nghĩ về điều đó đây)."},{"t":"example","text":"Как раз (đúng là/chính là)."},{"t":"para","text":"3. — Он пóнял, о чём ты егó прóсишь?","b":1},{"t":"para","text":"Trả lời: — Вря́д ли он пóнял. (Tôi e là/ngờ rằng nó không hiểu)."},{"t":"example","text":"Вря́д ли (khó mà/e là không - biểu thị sự nghi ngờ mạnh)."},{"t":"para","text":"4. — Где же ваш друг, о котóром вы так мнóго разскáзывали?","b":1},{"t":"para","text":"Trả lời: — Вот он идёт! (Kìa anh ấy đang đi tới!)."},{"t":"example","text":"Вот (kìa/đây - chỉ định)."},{"t":"para","text":"5. — Он тебя́ вы́слушал до концá?","b":1},{"t":"para","text":"Trả lời: — Дáже не стал слýшать! (Anh ta thậm chí còn chẳng thèm nghe!)."},{"t":"example","text":"Дáже (thậm chí - nhấn mạnh mức độ bất ngờ)."},{"t":"para","text":"6. — Ты поздра́вил егó с днём рождéния?","b":1},{"t":"para","text":"Trả lời: — Ещё не успéл. (Tôi vẫn chưa kịp)."},{"t":"example","text":"Ещё (vẫn/chưa - chỉ thời gian)."},{"t":"para","text":"7. — Э́ту корóбку нáдо нестú осторóжно?","b":1},{"t":"para","text":"Trả lời: — А то как же! Там стеклó. (Tất nhiên rồi/Chứ sao nữa! Trong đó là thủy tinh)."},{"t":"example","text":"А то как же (dĩ nhiên rồi)."},{"t":"vocab","ru":"— Что мне дéлать прéжде всегó","vi":"сходúть в магазúн и́ли вы́мыть посýду?","g":null},{"t":"para","text":"Trả lời: — Лýчше сходú в магазúн. (Tốt hơn là hãy đi cửa hàng)."},{"t":"example","text":"Лýчше (tốt hơn - lời khuyên)."},{"t":"para","text":"9. — Ты встрéтился с нúми вчерá вéчером?","b":1},{"t":"para","text":"Trả lời: — Тóлько по телефóну поговорúли. (Chúng tôi chỉ nói chuyện qua điện thoại thôi)."},{"t":"example","text":"Тóлько (chỉ - giới hạn)."},{"t":"para","text":"10. — Ты понимáешь, о чём он говорúт?","b":1},{"t":"para","text":"Trả lời: — Рéшительно ничегó не понимáю! (Tôi quả quyết/hoàn toàn chả hiểu gì cả!)."},{"t":"example","text":"Рéшительно (hoàn toàn/dứt khoát - nhấn mạnh phủ định)."}]},{"id":"06-s005","type":"exercise","title":"BÀI TẬP 483 (Trang 242)","num":483,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu văn. Xác định sự khác biệt về ý nghĩa của các tiểu từ được in đậm (hoặc nằm trong ngữ cảnh)."},{"t":"subhead","text":"Gợi ý ngữ pháp trong khung (Trang 242):","b":1},{"t":"vocab","ru":"Trong văn nói (разговорная речь) thường dùng các tiểu từ","vi":"мол, дéскать, -ка và các từ khác.","g":null},{"t":"vocab","ru":"мол / дéскать","vi":"Dùng để trích dẫn lời người khác hoặc lời đồn, mang ý nghĩa \"bảo là\", \"rằng là\".","g":null},{"t":"vocab","ru":"-ка","vi":"Gắn sau động từ mệnh lệnh để làm nhẹ bớt câu lệnh hoặc thể hiện sự thân mật (nào, đi, thử xem).","g":null},{"t":"example","text":"a) 1. Я не знал, что так полýчится, я ведь ничегó плохóго не хотéл сдéлать.","b":1},{"t":"example","text":"Dịch: Tôi không biết là sẽ thành ra như vậy, tôi đâu có (thực tình là) muốn làm gì xấu đâu."},{"t":"example","text":"Giải thích: Ведь dùng để biện minh, giải thích nguyên nhân mà người nói cho rằng người nghe nên hiểu."},{"t":"example","text":"2. Посидú спокóйно, дай мне отдохнýть хоть нéсколько минýт.","b":1},{"t":"example","text":"Dịch: Ngồi yên đi, để cho tôi nghỉ ngơi ít nhất là vài phút."},{"t":"example","text":"Giải thích: Хоть (ít nhất là/dù chỉ là) biểu thị mức độ tối thiểu."},{"t":"example","text":"3. Я не сплю ужé трéтьи сýтки.","b":1},{"t":"example","text":"Dịch: Tôi không ngủ đã ba ngày đêm rồi."},{"t":"example","text":"Giải thích: Ужé nhấn mạnh khoảng thời gian kéo dài."},{"t":"example","text":"4. Вы придёте к нам зáвтра? Ну конéчно, придём.","b":1},{"t":"example","text":"Dịch: Ngày mai các bạn đến chỗ chúng tôi chứ? Ồ tất nhiên, chúng tôi sẽ đến."},{"t":"example","text":"Giải thích: Ну dùng để tăng cường sự khẳng định."},{"t":"example","text":"5. Такáя же погóда былá здéсь в прóшлом годý.","b":1},{"t":"example","text":"Dịch: Thời tiết ở đây năm ngoái cũng y hệt như thế."},{"t":"example","text":"Giải thích: Же trong такая же biểu thị sự đồng nhất (giống hệt)."},{"t":"example","text":"6. Дáйте же мне сказáть!","b":1},{"t":"example","text":"Dịch: Hãy để cho tôi nói đi mà! (Cho tôi nói ngay!)."},{"t":"example","text":"Giải thích: Же đi với mệnh lệnh thể hiện sự nôn nóng, thúc giục mạnh mẽ."},{"t":"example","text":"7. — Пойдём с нáми! — Что ж, пойдём.","b":1},{"t":"example","text":"Dịch: — Đi với chúng tôi đi! — Thôi được/Chà, thì đi."},{"t":"example","text":"Giải thích: Что ж biểu thị sự đồng ý, chấp thuận (đôi khi hơi miễn cưỡng hoặc chấp nhận sự việc)."},{"t":"example","text":"8. Мы, навéрное не вóвремя пришлú? Как раз вóвремя, садúтесь с нáми пить чай.","b":1},{"t":"example","text":"Dịch: Chúng tôi đến không đúng lúc phải không? Đúng lúc lắm, ngồi xuống uống trà với chúng tôi đi."},{"t":"example","text":"Giải thích: Не dùng để tạo câu hỏi nghi vấn nhẹ nhàng hoặc phủ định."},{"t":"example","text":"9. Он далекó не мóлод, емý за трúдцать.","b":1},{"t":"example","text":"Dịch: Anh ấy chẳng trẻ trung gì đâu, anh ấy ngoài ba mươi rồi."},{"t":"example","text":"Giải thích: Далеко не (còn lâu mới/chẳng... chút nào) nhấn mạnh sự phủ định tính chất."},{"t":"example","text":"10. Пóезд отхóдит чéрез минýту, мы едвá (чуть) не опоздáли на негó!","b":1},{"t":"example","text":"Dịch: Tàu rời bến sau một phút nữa, chúng ta suýt chút nữa thì trễ tàu!"},{"t":"example","text":"Giải thích: Едвá не hoặc чуть не nghĩa là \"suýt nữa thì\", hành động gần như đã xảy ra nhưng may mắn là không."},{"t":"vocab","ru":"Я не бóлен, я прóсто óчень устáл немнóжко. (Lưu ý","vi":"trong sách gốc câu này có thể là: Я не болен, просто устал немного).","g":null},{"t":"example","text":"Dịch: Tôi không ốm, tôi đơn giản là hơi mệt một chút."},{"t":"example","text":"Giải thích: Немножко làm giảm nhẹ mức độ."},{"t":"example","text":"12. Как (Лишь) тóлько он вошёл, все замолчáли.","b":1},{"t":"example","text":"Dịch: Ngay khi anh ấy vừa bước vào, mọi người đều im lặng."},{"t":"example","text":"Giải thích: Как только hoặc Лишь только chỉ hành động xảy ra ngay lập tức sau hành động khác."},{"t":"example","text":"13. Всë нéбо покры́то тýчами, того́ и гляди́ (жди) пойдёт дождь.","b":1},{"t":"example","text":"Dịch: Cả bầu trời phủ đầy mây, trông chừng/khéo mà trời sắp mưa đến nơi rồi."},{"t":"example","text":"Giải thích: Того и гляди diễn tả một hành động sắp sửa xảy ra ngay lập tức (thường là điều e ngại)."},{"t":"example","text":"14. — Я не возрожáю. — Ещё бы ты возражáл, éсли сам во всём виновáт!","b":1},{"t":"example","text":"Dịch: — Tôi không phản đối. — Còn phải nói/Làm sao mà phản đối được, khi chính cậu là người có lỗi trong mọi chuyện!"},{"t":"example","text":"Giải thích: Ещё бы mang ý mỉa mai, khẳng định rằng việc đó là đương nhiên, không thể khác được."},{"t":"example","text":"15. — Хóчешь морóженого? Ещё бы! От морóженого я никогдá не откáзываюсь.","b":1},{"t":"example","text":"Dịch: — Muốn ăn kem không? — Còn phải hỏi/Tất nhiên rồi! Tớ chưa bao giờ từ chối kem cả."},{"t":"example","text":"Giải thích: Ещё бы ở đây thể hiện sự đồng ý nhiệt tình."},{"t":"example","text":"16. Есть я не бýду, рáзве тóлько вы́пью чáшку чáя.","b":1},{"t":"example","text":"Dịch: Tôi sẽ không ăn đâu, hoạ chăng chỉ uống một tách trà thôi."},{"t":"example","text":"Giải thích: Рáзве тóлько biểu thị sự ngoại lệ duy nhất hoặc khả năng nhỏ."},{"t":"example","text":"b) 1. Передaвáй емý от нас привéт, скажú, что, мол, пóмним егó, скучáем.","b":1},{"t":"example","text":"Dịch: Hãy gửi lời chào của chúng tôi đến anh ấy, nói rằng, là, chúng tôi nhớ anh ấy, mong gặp."},{"t":"example","text":"Giải thích: Мол dùng để đánh dấu lời nói gián tiếp (rằng là/bảo là)."},{"t":"example","text":"2. Мы все егó уговáривали поéхать, а он не хóчет, говорúт, дéскать, другúе делá есть.","b":1},{"t":"example","text":"Dịch: Tất cả chúng tôi đều thuyết phục anh ấy đi, nhưng anh ấy không muốn, nói rằng là có việc khác rồi."},{"t":"example","text":"Giải thích: Дéскать tương tự như мол, dùng để dẫn lời người khác, thường mang sắc thái hơi xa cách hoặc không tin tưởng lắm."},{"t":"example","text":"3. Займúсь-ка ты дéлом, устáл, навéрное, отдыхáть.","b":1},{"t":"example","text":"Dịch: Này, cậu bắt tay vào làm việc đi, chắc là nghỉ ngơi chán rồi chứ gì."},{"t":"example","text":"Giải thích: -ка làm cho câu mệnh lệnh trở nên mềm mỏng hơn, mang tính khích lệ hoặc thân mật."},{"t":"example","text":"4. Срáзу вúдно, не простóй он человéк, эк как красúво расскáзывает.","b":1},{"t":"example","text":"Dịch: Thấy ngay mà, ông ta không phải người thường đâu, chà, kể chuyện mới hay làm sao."},{"t":"example","text":"Giải thích: Эк là tiểu từ cảm thán dân dã, biểu thị sự ngạc nhiên, thán phục (Chà/Gớm)."},{"t":"example","text":"5. Дня э́так чéрез два мы отсю́да уéдем.","b":1},{"t":"example","text":"Dịch: Khoảng chừng hai ngày nữa chúng tôi sẽ rời khỏi đây."},{"t":"example","text":"Giải thích: Этак (hoặc так) dùng với thời gian/số lượng để chỉ sự ước lượng, xấp xỉ."}]},{"id":"06-s006","type":"exercise","title":"BÀI TẬP 484 (Trang 242)","num":484,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền các tiểu từ thích hợp vào chỗ trống (мол, дескать, -ка và các tiểu từ khác đã học). Giải thích sự lựa chọn."},{"t":"para","text":"1. Éсли другúх предложéний нет, что ж (hoặc ну), давáй попрóбуем твой мéтод.","b":1},{"t":"example","text":"Dịch: Nếu không còn đề xuất nào khác, thôi được/nào, hãy thử phương pháp của bạn."},{"t":"example","text":"Giải thích: Что ж biểu thị sự chấp thuận sau khi cân nhắc hoặc không còn lựa chọn khác."},{"t":"para","text":"2. Знáешь, вчерá я чуть (hoặc едвá) не забýл о твоéй прóсьбе, хорошó, что Вúктор мне о ней напóмнил.","b":1},{"t":"example","text":"Dịch: Biết không, hôm qua tôi suýt nữa thì quên mất lời thỉnh cầu của bạn, may mà Viktor đã nhắc tôi."},{"t":"example","text":"Giải thích: Чуть не (suýt nữa thì) dùng cho hành động tiêu cực suýt xảy ra."},{"t":"para","text":"3. Сходú-ка ты в магазúн, купú чтó-нибудь к чáю.","b":1},{"t":"example","text":"Dịch: Con (em/bạn) chạy ù ra cửa hàng đi, mua cái gì đó để uống trà."},{"t":"example","text":"Giải thích: -ка dùng trong câu mệnh lệnh thân mật (nhờ vả nhẹ nhàng)."},{"t":"para","text":"4. Лишь (hoặc Как) тóлько мы вы́шли из дóма, пошёл дождь.","b":1},{"t":"example","text":"Dịch: Ngay khi chúng tôi vừa ra khỏi nhà thì trời mưa."},{"t":"example","text":"Giải thích: Лишь только hoặc Как только chỉ mốc thời gian ngay lập tức."},{"t":"para","text":"5. Зачéм емý приходúть зáвтра вмéсте с нáми, он ведь ужé сдал экзáмен.","b":1},{"t":"example","text":"Dịch: Cậu ấy đến ngày mai cùng chúng ta làm gì, cậu ấy đã thi xong rồi cơ mà."},{"t":"example","text":"Giải thích: Ведь dùng để giải thích lý do (vì/cơ mà), điều mà người nói nghĩ là hiển nhiên."},{"t":"para","text":"6. — Ты емý сообщúла о зáвтрашней встрéче? — Ну конéчно, он знáет об э́том.","b":1},{"t":"example","text":"Dịch: — Bạn đã báo cho anh ấy về cuộc gặp ngày mai chưa? — Ồ tất nhiên rồi, anh ấy biết chuyện đó."},{"t":"example","text":"Giải thích: Ну tăng cường ý khẳng định."},{"t":"para","text":"7. Позвонú мне зáвтра часóв э́так в вóсемь.","b":1},{"t":"example","text":"Dịch: Mai gọi cho tôi vào tầm khoảng 8 giờ nhé."},{"t":"example","text":"Giải thích: Этак đứng trước số từ chỉ sự ước lượng (tầm/khoảng)."},{"t":"para","text":"8. Он сказáл, что, мол (hoặc дéскать), емý не нрáвится нáше предложéние.","b":1},{"t":"example","text":"Dịch: Anh ta nói rằng là anh ta không thích đề xuất của chúng tôi."},{"t":"example","text":"Giải thích: Мол dùng để tường thuật lại lời người khác (mang sắc thái kể lại)."},{"t":"para","text":"9. Не знáю, что с ним дéлать! Того́ и гляди́ провáлит все вступúтельные экзáмены.","b":1},{"t":"example","text":"Dịch: Tôi không biết làm gì với nó nữa! Khéo mà/Coi chừng nó trượt hết các kỳ thi đầu vào mất."},{"t":"example","text":"Giải thích: Того и гляди diễn tả lo ngại về một việc sắp xảy ra."},{"t":"para","text":"10. Эк (hoặc Как) красúво он говорúт! Не срáзу и поймёшь егó.","b":1},{"t":"para","text":"Dịch: Hắn nói mới hay/hoa mỹ làm sao! Không phải lúc nào cũng hiểu ngay được hắn."},{"t":"example","text":"Giải thích: Эк hoặc Как dùng để cảm thán."},{"t":"para","text":"11. — Ты пойдёшь зáвтра на вéчер? — Вряд ли! Я так дóлго к немý готóвился.","b":1},{"t":"note","text":"Lưu ý ngữ cảnh: Câu trả lời \"Tôi đã chuẩn bị rất lâu\" có vẻ mâu thuẫn với \"Vряд ли\" (E là không). Nếu chuẩn bị lâu thì phải đi chứ?"},{"t":"example","text":"Sửa lại theo ngữ cảnh hợp lý hơn: Nếu vế sau là \"Я так долго... готовился\" (ý là chuẩn bị bài vở, bận rộn) thì Вряд ли đúng. Nếu ý là \"Tôi đã chuẩn bị cho buổi dạ hội\" thì phải là Ещё бы (Đi chứ sao không)."},{"t":"vocab","ru":"Dịch (theo hướng \"Ещё бы\")","vi":"— Mai bạn đi dự tiệc tối chứ? — Tất nhiên rồi! Tớ đã chuẩn bị cho nó lâu thế cơ mà.","g":null},{"t":"example","text":"Giải thích: Ещё бы (Tất nhiên/Chắc chắn)."},{"t":"para","text":"12. Что мог сказáть мне врач?! Соблюдáйте, мол (hoặc дéскать), диéту, берегúте себя́, не переутомля́йтесь.","b":1},{"t":"example","text":"Dịch: Bác sĩ có thể nói gì với tôi chứ?! Rằng thì là hãy ăn kiêng, giữ gìn sức khỏe, đừng làm việc quá sức."},{"t":"example","text":"Giải thích: Мол dùng để liệt kê lời khuyên của người khác (bác sĩ)."},{"t":"para","text":"13. Я не могý поня́ть, почемý он так поступúл, он ведь знал обо всём зарáнее.","b":1},{"t":"example","text":"Dịch: Tôi không thể hiểu tại sao anh ta lại hành động như vậy, anh ta đã biết trước mọi chuyện rồi cơ mà."},{"t":"example","text":"Giải thích: Ведь giải thích nguyên nhân (đã biết rồi)."},{"t":"example","text":"14. Не говорú мне о делáх, в выходны́е дни дай мне отдохнýть. (Câu này không có chỗ trống trong bản gốc, có thể là câu dẫn). Nếu cần điền: ...дай-ка мне... (hãy để cho tôi...)."},{"t":"para","text":"15. Я никудá не уйдý, разве тóлько вы́йду посмотрéть, не вернýлась ли машúна.","b":1},{"t":"example","text":"Dịch: Tôi sẽ không đi đâu cả, hoạ chăng chỉ ra ngoài xem xe đã về chưa thôi."},{"t":"example","text":"Giải thích: Разве только (chỉ trừ khi/hoạ chăng)."},{"t":"example","text":"16. Он стáрше тебя́ и óпытнее. (Không cần tiểu từ đặc biệt, hoặc и là liên từ). Nếu là nhấn mạnh: Он ведь старше... (Anh ấy lớn hơn cậu mà...)."},{"t":"example","text":"Giả định: Он старше тебя и, пожа́луй, опытнее (Anh ấy lớn hơn và có lẽ kinh nghiệm hơn)."},{"t":"para","text":"17. Говорúть с ним дóлго я не бýду, так, поздрáвлю егó с прáздником.","b":1},{"t":"example","text":"Dịch: Tôi sẽ không nói chuyện lâu với anh ấy đâu, chỉ là chúc mừng ngày lễ thôi."},{"t":"example","text":"Giải thích: Так (chỉ là/đại khái thế) dùng để giảm nhẹ tầm quan trọng của hành động."}]},{"id":"06-s007","type":"exercise","title":"BÀI TẬP 485 (Trang 243)","num":485,"blocks":[{"t":"instruction","text":"Yêu cầu: Trả lời các câu hỏi, sử dụng các tiểu từ cần thiết theo ý nghĩa."},{"t":"para","text":"1. — Что он отвéтил на твоё предложéние?","b":1},{"t":"para","text":"Trả lời: — Сказáл, что, мол, подýмает."},{"t":"example","text":"Dịch: — Anh ta trả lời thế nào về đề nghị của cậu? — Anh ta bảo rằng là sẽ suy nghĩ."},{"t":"example","text":"Giải thích: Мол dùng để thuật lại lời nói."},{"t":"para","text":"2. — Ты зарáнее знал обо всём?","b":1},{"t":"para","text":"Trả lời: — Ну конéчно (знал)."},{"t":"example","text":"Dịch: — Cậu biết trước mọi chuyện à? — Thì tất nhiên rồi."},{"t":"example","text":"Giải thích: Ну khẳng định."},{"t":"para","text":"3. — Ты забýл о моéй прóсьбе?","b":1},{"t":"para","text":"Trả lời: — Чуть было не забýл."},{"t":"example","text":"Dịch: — Cậu quên lời thỉnh cầu của tớ rồi à? — Suýt chút nữa thì quên."},{"t":"example","text":"Giải thích: Чуть было не (suýt nữa thì)."},{"t":"para","text":"4. — Попрóбуешь торт, котóрый я приготóвила?","b":1},{"t":"para","text":"Trả lời: — Ещё бы! С удoвóльствием."},{"t":"example","text":"Dịch: — Cậu sẽ thử bánh tớ làm chứ? — Chắc chắn rồi! Rất sẵn lòng."},{"t":"example","text":"Giải thích: Ещё бы (tất nhiên/còn phải hỏi)."},{"t":"para","text":"5. — Как погóда?","b":1},{"t":"para","text":"Trả lời: — Что за погóда! Прóсто ýжас. (Hoặc: Ну и погóда!)."},{"t":"example","text":"Dịch: — Thời tiết thế nào? — Thời tiết kiểu gì thế này! Kinh khủng quá."},{"t":"example","text":"Giải thích: Что за / Ну и dùng để cảm thán."},{"t":"para","text":"6. — Снег ещё лежúт на поля́х?","b":1},{"t":"para","text":"Trả lời: — Ужé растáял."},{"t":"example","text":"Dịch: — Tuyết vẫn còn trên cánh đồng à? — Tan đã lâu rồi (Tan rồi)."},{"t":"example","text":"Giải thích: Уже (đã/rồi)."},{"t":"para","text":"7. — Снегá почтú нет, ... ? (Câu hỏi đuôi)."},{"t":"example","text":"Trả lời hoàn chỉnh câu hỏi: — Снега почти нет, не прáвда ли? (Tuyết gần như không còn, đúng không?)."},{"t":"para","text":"Dịch: Tuyết gần như hết rồi, phải không?"},{"t":"para","text":"8. — Мóжет быть, поéдем отдыхáть вмéсте?","b":1},{"t":"para","text":"Trả lời: — Что ж, давáй поéдем."},{"t":"example","text":"Dịch: — Hay là chúng ta đi nghỉ cùng nhau đi? — Được thôi, đi thì đi."},{"t":"example","text":"Giải thích: Что ж biểu thị sự đồng thuận."},{"t":"para","text":"9. — Чем мне заня́ться?","b":1},{"t":"para","text":"Trả lời: — Почитáй-ка кнúгу."},{"t":"example","text":"Dịch: — Tôi nên làm gì đây? — Đọc sách đi/thử xem."},{"t":"example","text":"Giải thích: -ка làm mềm câu khuyên bảo."},{"t":"para","text":"10. — Неужéли ты надéешься получúть у негó автóграф?","b":1},{"t":"para","text":"Trả lời: — Вряд ли, но попрóбовать стóит."},{"t":"example","text":"Dịch: — Chẳng lẽ cậu hy vọng xin được chữ ký của ông ấy sao? — Khó lắm (E là không), nhưng đáng để thử."},{"t":"example","text":"Giải thích: Вряд ли biểu thị sự nghi ngờ cao."},{"t":"note","text":"Lưu ý chung:","b":1},{"t":"example","text":"Các từ trong tiếng Nga đã được đánh trọng âm (ví dụ: хóчется)."},{"t":"para","text":"Phần dịch tiếng Việt bám sát nghĩa gốc và ngữ cảnh giao tiếp tự nhiên."},{"t":"para","text":"Giải thích ngữ pháp tập trung vào chức năng của \"Tiểu từ\" (Частицы) để học sinh hiểu cách dùng cảm xúc và sắc thái trong câu."},{"t":"para","text":"Chào em, đây là phần giải thích chi tiết, dịch thuật và hướng dẫn làm bài tập từ 486 đến 490 trong sách \"Грамматика русского языка в упражнениях и комментариях. Морфология\" (O. I. Glazunova), trang 243-245."},{"t":"para","text":"Tài liệu này tập trung vào các Tiểu từ (Частицы), đặc biệt là sự phân biệt giữa các cặp từ dễ nhầm lẫn như и́менно / как рáз và рáзве / неужéли."}]},{"id":"06-s008","type":"grammar","title":"PHẦN NGỮ PHÁP (Trang 243)","num":null,"blocks":[{"t":"para","text":"Trước khi vào bài tập, chúng ta cần hiểu rõ lý thuyết trong khung ngữ pháp của bài 486 và 491."},{"t":"para","text":"1. Cặp tiểu từ И́МЕННО và КАК РÁЗ (Chính là / Đúng là)","b":1},{"t":"vocab","ru":"И́менно (Chính, cụ thể là)","vi":"Dùng để xác định chính xác, nhấn mạnh vào đối tượng, thời gian, hoặc địa điểm cụ thể (trả lời cho câu hỏi: Ai cụ thể? Ở đâu cụ thể? Khi nào cụ thể?). Nó mang tính chất định danh, làm rõ thông tin.","g":null},{"t":"example","text":"Ví dụ: И́менно он (Chính anh ta - chứ không phải ai khác)."},{"t":"vocab","ru":"Как рáз (Đúng là, vừa vặn, vừa hay)","vi":"Dùng để chỉ sự trùng hợp, sự thích hợp, vừa vặn về thời gian hoặc đặc điểm, hoặc mang ý nghĩa \"đúng cái mà mình cần/đang nói tới\". Thường mang sắc thái ngẫu nhiên hoặc thỏa mãn mong đợi.","g":null},{"t":"example","text":"Ví dụ: Ботíнки мне как рáз (Đôi giày vừa khít với tôi). Я как рáз дýмал о тебé (Tớ vừa hay đang nghĩ về cậu)."},{"t":"para","text":"2. Cặp tiểu từ РÁЗВЕ và НЕУЖÉЛИ (Chẳng lẽ / Thật ư)","b":1},{"t":"vocab","ru":"Рáзве (Chẳng lẽ... hay sao?)","vi":"Dùng khi người nói nghi ngờ thông tin, muốn hỏi lại để xác nhận xem điều mình nghĩ có đúng không (thường tin vào điều ngược lại hoặc không chắc chắn).","g":null},{"t":"example","text":"Ví dụ: Рáзве ты не знáешь? (Chẳng lẽ cậu không biết à? - Tôi tưởng cậu biết chứ)."},{"t":"vocab","ru":"Неужéли (Thật ư? / Chẳng lẽ lại...?)","vi":"Dùng để biểu thị sự ngạc nhiên cao độ, sững sờ, khó tin vào điều đang diễn ra hoặc vừa nghe thấy.","g":null},{"t":"example","text":"Ví dụ: Неужéли э́то прáвда? (Thật sự là sự thật sao? - Không thể tin được)."}]},{"id":"06-s009","type":"exercise","title":"BÀI TẬP 486 (Trang 243)","num":486,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu văn. Xác định sự khác biệt về ý nghĩa của các tiểu từ и́менно và как рáз."},{"t":"para","text":"a) Nhóm dùng \"И́менно\" (Nhấn mạnh sự chính xác, cụ thể)","b":1},{"t":"para","text":"1. Онá пéрвой рассказáла мне э́ту нóвость. И́менно онá пéрвой рассказáла мне э́ту нóвость.","b":1},{"t":"para","text":"Dịch: Cô ấy là người đầu tiên kể cho tôi tin này. Chính cô ấy là người đầu tiên kể cho tôi tin này."},{"t":"para","text":"Giải thích: Nhấn mạnh chủ ngữ (chính cô ấy chứ không phải người khác)."},{"t":"para","text":"2. В э́том дóме живýт мои́ родúтели. И́менно в э́том дóме живýт мои́ родúтели.","b":1},{"t":"para","text":"Dịch: Bố mẹ tôi sống trong ngôi nhà này. Chính trong ngôi nhà này bố mẹ tôi đang sống."},{"t":"para","text":"Giải thích: Nhấn mạnh địa điểm cụ thể."},{"t":"para","text":"3. Мне нýжен голубóй шарф, а не зелёный. Мне нýжен и́менно голубóй шарф, а не зелёный.","b":1},{"t":"para","text":"Dịch: Tôi cần cái khăn màu xanh da trời chứ không phải màu xanh lá. Tôi cần chính xác là cái khăn màu xanh da trời, chứ không phải xanh lá."},{"t":"para","text":"Giải thích: Nhấn mạnh sự lựa chọn cụ thể."},{"t":"para","text":"4. Он вчерá говорúл нам об э́том. Он и́менно вчерá говорúл нам об э́том.","b":1},{"t":"para","text":"Dịch: Hôm qua anh ấy đã nói với chúng tôi về việc đó. Chính hôm qua anh ấy đã nói với chúng tôi về việc đó."},{"t":"para","text":"Giải thích: Nhấn mạnh thời gian chính xác."},{"t":"para","text":"5. Где ты рáньше рабóтал? Где и́менно ты рáньше рабóтал?","b":1},{"t":"para","text":"Dịch: Trước đây cậu làm việc ở đâu? Cậu làm việc cụ thể là ở đâu trước đây?"},{"t":"para","text":"Giải thích: Yêu cầu thông tin chi tiết, chính xác."},{"t":"para","text":"6. Он закричáл, а не прóсто повы́сил на нас гóлос. Он и́менно закричáл, а не прóсто повы́сил на нас гóлос.","b":1},{"t":"para","text":"Dịch: Hắn ta hét lên, chứ không đơn giản là to tiếng với chúng tôi. Hắn ta thực sự/chính xác là đã hét lên..."},{"t":"para","text":"Giải thích: Làm rõ tính chất hành động."},{"t":"para","text":"b) Nhóm dùng \"Как рáз\" (Nhấn mạnh sự trùng hợp, vừa vặn, \"đúng là\")","b":1},{"t":"para","text":"1. Он знал об э́том зарáнее. Как рáз он знал об э́том зарáнее.","b":1},{"t":"para","text":"Dịch: Anh ta biết trước về điều đó. Đúng là/Vừa hay anh ta đã biết trước về điều đó (hoặc: Chính anh ta là người biết trước - trong ngữ cảnh đối lập với người khác không biết)."},{"t":"para","text":"2. С э́того дня всё измени́лось в нáшей жúзни; С э́того дня всё измени́лось в нáшей жúзни. Как рáз с э́того дня всё измени́лось в нáшей жúзни.","b":1},{"t":"para","text":"Dịch: Kể từ ngày đó mọi thứ trong cuộc sống chúng tôi đã thay đổi. Đúng từ ngày đó mọi thứ trong cuộc sống chúng tôi đã thay đổi."},{"t":"para","text":"3. Слáдкий чай я не люблю́. Как рáз слáдкий чай я не люблю́.","b":1},{"t":"para","text":"Dịch: Tôi không thích trà ngọt. Đúng cái món trà ngọt là tôi không thích (Vừa hay nhắc đến trà ngọt thì đó lại là thứ tôi ghét)."},{"t":"para","text":"4. Кинотеáтр нахóдится на э́той сторонé ýлицы за углóм. Кинотеáтр нахóдится как рáз на э́той сторонé ýлицы за углóм.","b":1},{"t":"para","text":"Dịch: Rạp chiếu phim nằm ở phía bên này đường sau góc phố. Rạp chiếu phim nằm ngay đúng phía bên này đường sau góc phố."},{"t":"para","text":"5. Мы испрáвили э́ту ошúбку. Мы как рáз испрáвили э́ту ошúбку.","b":1},{"t":"para","text":"Dịch: Chúng tôi đã sửa lỗi này. Chúng tôi vừa mới/đúng là đã sửa lỗi này xong."}]},{"id":"06-s010","type":"exercise","title":"BÀI TẬP 487 (Trang 243)","num":487,"blocks":[{"t":"instruction","text":"Yêu cầu: Đặt câu hỏi cần thiết theo ý nghĩa cho các câu có tiểu từ и́менно và как рáз ở bài tập 486."},{"t":"example","text":"Nguyên tắc: Khi có и́менно hoặc как рáз đi kèm từ nào, ta đặt câu hỏi vào từ đó."},{"t":"para","text":"Câu a1: Кто и́менно рассказáл тебé э́ту нóвость? (Ai chính xác là người kể cho bạn tin này?)"},{"t":"para","text":"Câu a2: Где и́менно живýт твои́ родúтели? (Bố mẹ bạn sống chính xác ở đâu?)"},{"t":"para","text":"Câu a3: Какóй и́менно шарф тебé нýжен? (Bạn cần chính xác là cái khăn nào?)"},{"t":"para","text":"Câu a4: Когдá и́менно он говорúл вам об э́том? (Anh ấy nói với các bạn về điều đó chính xác là khi nào?)"},{"t":"example","text":"Câu a5: (Câu gốc đã là câu hỏi: Где и́менно ты рáньше рабóтал?)"},{"t":"para","text":"Câu a6: Что и́менно он сдéлал? (Anh ta chính xác đã làm gì?)"},{"t":"para","text":"Câu b1: Кто как рáз знал об э́том зарáнее? (Ai là người đúng ra đã biết trước?)"},{"t":"para","text":"Câu b2: С какóго (как рáз) дня всё измени́лось? (Mọi thứ thay đổi đúng từ ngày nào?)"},{"t":"para","text":"Câu b3: Какóй (как рáз) чай ты не лю́бишь? (Đúng loại trà nào cậu không thích?)"},{"t":"para","text":"Câu b4: Где как рáз нахóдится кинотеáтр? (Rạp phim nằm đúng ở đâu?)"},{"t":"para","text":"Câu b5: Какýю (как рáз) ошúбку вы испрáвили? (Các bạn đã sửa đúng lỗi nào?)"}]},{"id":"06-s011","type":"exercise","title":"BÀI TẬP 488 (Trang 244)","num":488,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền tiểu từ thích hợp (и́менно hoặc как рáз) vào chỗ trống."},{"t":"subhead","text":"Gợi ý: Именно dùng để định danh chính xác (identifying). Как раз dùng để chỉ sự trùng hợp, vừa vặn hoặc đối lập nhẹ (coincidence/suitability)."},{"t":"para","text":"1. Он и́менно вчерá уéхал из гóрода.","b":1},{"t":"para","text":"Dịch: Anh ấy chính xác là hôm qua đã rời thành phố. (Xác định thời gian)."},{"t":"para","text":"2. Э́то как рáз скóро и должнó произойтú.","b":1},{"t":"para","text":"Dịch: Điều này đúng là/vừa hay sắp phải xảy ra rồi. (Sự trùng hợp thời điểm)."},{"t":"para","text":"3. Я не могý с тобóй поéхать, и́менно в два часá мы встречáемся в университéте с мои́м наýчным руководúтелем.","b":1},{"t":"para","text":"Dịch: Tớ không đi với cậu được, chính xác vào lúc 2 giờ chúng tớ gặp giáo viên hướng dẫn ở trường. (Xác định mốc giờ cụ thể không thể thay đổi)."},{"t":"para","text":"4. Мне нýжен и́менно голубóй шарф, а не зелёный.","b":1},{"t":"para","text":"Dịch: Tôi cần chính xác cái khăn màu xanh, chứ không phải màu lục. (Sự lựa chọn cụ thể)."},{"t":"para","text":"5. Мы как рáз отдыхáли в Крыму́ прóшлым лéтом.","b":1},{"t":"para","text":"Dịch: Chúng tôi vừa hay/đúng là đã nghỉ ở Crưm mùa hè trước. (Sự trùng hợp ngẫu nhiên khi nói chuyện)."},{"t":"example","text":"6. Такáя мéбель нам нужнá; и́менно такáя мéбель нам и нужнá. (Hoặc как раз tùy ngữ cảnh, nhưng именно mạnh hơn về sự xác định)."},{"t":"para","text":"Chọn: и́менно (để nhấn mạnh \"chính loại này\")."},{"t":"para","text":"Dịch: Chính loại nội thất như thế này là thứ chúng tôi cần."},{"t":"para","text":"7. Он приходи́л и́менно по дéлу, емý нýжен был отчёт за прóшлый год.","b":1},{"t":"para","text":"Dịch: Anh ấy đến chính xác/cụ thể là vì công việc, anh ấy cần báo cáo năm ngoái."},{"t":"para","text":"8. Мы вернýлись домóй как рáз вóвремя.","b":1},{"t":"example","text":"Dịch: Chúng tôi về nhà vừa đúng lúc. (Thành ngữ как раз вовремя - just in time)."},{"t":"para","text":"9. Он и́менно трéбовал, чтóбы я тудá поéхал, а не просúл.","b":1},{"t":"para","text":"Dịch: Hắn ta thực sự là/chính xác là đã ra lệnh cho tôi đi, chứ không phải là nhờ vả. (Làm rõ tính chất hành động)."},{"t":"para","text":"10. Э́то нахóдится как рáз побли́зости от вáшего дóма.","b":1},{"t":"para","text":"Dịch: Chỗ đó nằm ngay đúng/vừa hay ở gần nhà bạn. (Sự thuận tiện, trùng hợp địa điểm)."},{"t":"para","text":"11. И́менно вездé и испóльзуется э́тот вариáнт.","b":1},{"t":"para","text":"Dịch: Chính xác là biến thể này được sử dụng ở khắp mọi nơi."},{"t":"para","text":"12. ...тут всё и произошлó, и́менно в двух шагáх от э́того дóма.","b":1},{"t":"para","text":"Dịch: ...mọi chuyện đã xảy ra ở đây, chính xác là cách ngôi nhà này hai bước chân."},{"t":"para","text":"13. О твоéй прóсьбе я как рáз пóмню, не беспокóйся.","b":1},{"t":"para","text":"Dịch: Về lời thỉnh cầu của cậu thì tớ đúng là/vẫn đang nhớ đây, đừng lo. (Trấn an, đúng cái đang quan tâm)."},{"t":"para","text":"14. И́менно сегóдня я хотéл бы взять выходнóй.","b":1},{"t":"para","text":"Dịch: Chính/Cụ thể là hôm nay tôi muốn xin nghỉ."},{"t":"para","text":"15. А мне э́тот ромáн как рáз понрáвился.","b":1},{"t":"para","text":"Dịch: Nhưng tôi thì lại thích cuốn tiểu thuyết này (vừa hay tôi lại thích - ý ngược lại với người chê)."},{"t":"para","text":"16. Извинú, я не могý с тобóй поéхать, как рáз сегóдня я зáнят.","b":1},{"t":"para","text":"Dịch: Xin lỗi, tớ không đi cùng cậu được, đúng hôm nay tớ lại bận. (Trùng hợp không may)."},{"t":"para","text":"17. Он пришёл и́менно (hoặc как рáз) накану́не нáшего отъéзда.","b":1},{"t":"example","text":"Dịch: Anh ấy đến ngay/đúng vào đêm trước khi chúng tôi đi. (Nếu nhấn mạnh thời điểm chính xác: именно; nếu nhấn mạnh sự trùng hợp ngẫu nhiên: как раз). Ưu tiên: как раз."},{"t":"para","text":"18. Скажú мне, кто и́менно сообщúл тебé об э́том.","b":1},{"t":"para","text":"Dịch: Nói cho tôi biết, chính xác là ai đã báo cho bạn việc này. (Yêu cầu định danh)."}]},{"id":"06-s012","type":"exercise","title":"BÀI TẬP 489 (Trang 244)","num":489,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền tiểu từ thích hợp vào chỗ trống (и́менно hoặc как рáз)."},{"t":"para","text":"1. Почемý ты меня́ не слýшаешь, я как рáз желáю тебé тóлько добрá.","b":1},{"t":"para","text":"Dịch: Sao con/bạn không nghe tôi, tôi thực tình/đúng là chỉ muốn tốt cho bạn thôi."},{"t":"para","text":"2. Я не хочý с ним встречáться. — А тебé и́менно (hoặc как рáз) стóит с ним встрéтиться.","b":1},{"t":"para","text":"Dịch: Tớ không muốn gặp hắn. — Nhưng cậu chính là/lại càng cần phải gặp hắn. (Khuyên nhủ, nhấn mạnh)."},{"t":"para","text":"3. Ты смóжешь прийтú к нам в суббóту? — И́менно в суббóту я свобóден, придý обязáтельно.","b":1},{"t":"para","text":"Dịch: — Cậu đến chỗ tớ vào thứ Bảy được không? — Chính thứ Bảy tớ rảnh, tớ chắc chắn sẽ đến. (Xác nhận thời gian cụ thể)."},{"t":"para","text":"4. Вы́глядишь ты прекрáсно, ... кинозвездá!","b":1},{"t":"example","text":"Điền: и́менно / пря́мо (bài này đang luyện именно/как раз, nhưng văn cảnh này hợp với прямо - cứ như là. Nếu bắt buộc chọn trong 2 từ kia thì khó hợp lý. Có thể sách in nhầm hoặc muốn dùng как trong nghĩa so sánh)."},{"t":"note","text":"Lưu ý: Nếu dùng как раз, nghĩa là \"đúng là\". -> ты как рáз кинозвездá (trông cậu đúng là ngôi sao điện ảnh)."},{"t":"para","text":"5. Нет, я никудá не спешý, как рáз не хочý вас задéрживать.","b":1},{"t":"para","text":"Dịch: Không, tôi không vội đi đâu cả, chẳng qua/đúng là tôi không muốn giữ chân các bạn thôi."},{"t":"para","text":"6. Он пришёл и́менно (hoặc как рáз) в то врéмя, когдá егó ждáли.","b":1},{"t":"para","text":"Dịch: Anh ấy đến chính/đúng vào lúc người ta đang đợi."},{"t":"para","text":"7. Я как рáз не могý с тобóй согласúться!","b":1},{"t":"para","text":"Dịch: Tớ lại/đúng là không thể đồng ý với cậu! (Phản bác)."},{"t":"para","text":"8. ... óтпуск, я так устáл! -> Как рáз óтпуск... (Đúng là kỳ nghỉ tôi cần...)."},{"t":"para","text":"9. Мы как рáз не так наúвны, как вы дýмаете.","b":1},{"t":"para","text":"Dịch: Chúng tôi thực ra/đúng là không ngây thơ như các ông tưởng đâu."},{"t":"para","text":"10. Извинú, мы óчень торóпимся! — Я как рáз не задержа́ вас надóлго.","b":1},{"t":"para","text":"Dịch: Xin lỗi, chúng tôi vội lắm! — Tôi sẽ không giữ các bạn lâu đâu (đúng ý các bạn muốn)."},{"t":"para","text":"11. ... часы́ пробúли два, вся семья́ собрáлась в столо́вой. -> Как рáз (Vừa đúng lúc đồng hồ điểm 2 giờ...)."},{"t":"para","text":"12. Я как рáз остáвил в теáтре...","b":1},{"t":"para","text":"Dịch: Tôi đúng là/vừa hay đã để quên ở nhà hát..."},{"t":"example","text":"13. Ты не пóмнишь, он взял с собóй зóнтик? — Он лежáл в егó сýмке, тóчно не пóмню. (Chỗ trống này có vẻ không cần именно/как раз mà cần chủ ngữ hoặc hư từ khác. Nếu điền: И́менно он лежал... -> Chính nó nằm trong túi...)."},{"t":"para","text":"14. Скóлько мóжно смотрéть телевúзор?! — Как рáз займу́сь домáшним задáнием.","b":1},{"t":"para","text":"Dịch: Xem tivi mãi thế?! — Con đang định/sắp làm bài tập đây (Vừa hay con định làm)."},{"t":"para","text":"15. Когдá он мне об э́том сказáл, я как рáз засты́л на мéсте от удивлéния.","b":1},{"t":"para","text":"Dịch: Khi anh ấy nói với tôi điều đó, tôi đúng là chết sững vì ngạc nhiên."},{"t":"para","text":"16. Послýшайте ... меня́ немнóго, не кричúте! -> Послушайте и́менно меня... (Hãy nghe chính tôi đây...)."},{"t":"para","text":"17. Я вы́шел на минýту, я не знал, что он позвонúт и́менно в э́то врéмя.","b":1},{"t":"para","text":"Dịch: Tôi ra ngoài một phút, tôi không biết anh ấy sẽ gọi chính xác vào lúc đó."}]},{"id":"06-s013","type":"exercise","title":"BÀI TẬP 490 (Trang 245)","num":490,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu văn, xác định chức năng của các tiểu từ được in đậm. (Phân biệt các loại tiểu từ)."},{"t":"para","text":"a)","b":1},{"t":"vocab","ru":"Же (trong мы же не можем)","vi":"Tiểu từ nhấn mạnh (nhưng mà/cơ mà).","g":null},{"t":"vocab","ru":"Ни (trong ни один)","vi":"Tiểu từ phủ định mạnh (không một ai).","g":null},{"t":"vocab","ru":"Не (trong не мороз)","vi":"Tiểu từ phủ định (không phải).","g":null},{"t":"vocab","ru":"Рад не рад","vi":"Cấu trúc nhượng bộ (dù muốn hay không).","g":null},{"t":"vocab","ru":"Да","vi":"Khẳng định (vâng/có).","g":null},{"t":"vocab","ru":"Нет, не","vi":"Phủ định.","g":null},{"t":"para","text":"б)","b":1},{"t":"vocab","ru":"Неужéли","vi":"Tiểu từ nghi vấn biểu thị sự ngạc nhiên mạnh (Chẳng lẽ.../Thật ư...).","g":null},{"t":"vocab","ru":"Рáзве","vi":"Tiểu từ nghi vấn (Chẳng lẽ...).","g":null},{"t":"vocab","ru":"Давнó ли","vi":"Tiểu từ nghi vấn thời gian (Đã lâu chưa...).","g":null},{"t":"para","text":"в)","b":1},{"t":"vocab","ru":"Пусть (пускáй)","vi":"Tiểu từ tạo lập mệnh lệnh (hãy để/cầu cho).","g":null},{"t":"vocab","ru":"Пусть (пускáй)","vi":"(như trên).","g":null},{"t":"vocab","ru":"Да","vi":"Tiểu từ cảm thán/ước muốn (trong Да будет свет - Cầu cho có ánh sáng / Ánh sáng hãy hiện ra).","g":null},{"t":"vocab","ru":"Давáй","vi":"Tiểu từ tạo mệnh lệnh rủ rê (Hãy/Chúng ta hãy).","g":null},{"t":"vocab","ru":"Давáйте","vi":"(như trên, trang trọng/số nhiều).","g":null},{"t":"vocab","ru":"Лишь (Тóлько) бы","vi":"Tiểu từ mong ước (Giá mà/Miễn là).","g":null},{"t":"para","text":"г)","b":1},{"t":"vocab","ru":"Бы","vi":"Tiểu từ tạo thể giả định/điều kiện (nếu... thì sẽ...).","g":null},{"t":"vocab","ru":"Бы","vi":"(như trên).","g":null},{"t":"vocab","ru":"Бы","vi":"(như trên).","g":null},{"t":"vocab","ru":"Бы","vi":"(như trên).","g":null},{"t":"para","text":"д)","b":1},{"t":"vocab","ru":"Что за","vi":"Tiểu từ cảm thán (Cái gì mà/Thật là...).","g":null},{"t":"vocab","ru":"Ни","vi":"Phủ định (không chút nào).","g":null},{"t":"vocab","ru":"Как","vi":"Cảm thán (Biết bao/Làm sao).","g":null},{"t":"vocab","ru":"Как","vi":"Cảm thán (trong so sánh).","g":null}]},{"id":"06-s014","type":"exercise","title":"BÀI TẬP 491 (Trang 245)","num":491,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền рáзве hoặc неужéли vào chỗ trống. Giải thích sự lựa chọn."},{"t":"subhead","text":"Quy tắc:"},{"t":"para","text":"Рáзве = Tôi nghĩ ngược lại, tôi đang nghi ngờ thông tin này, tôi muốn hỏi lại (Chẳng lẽ...?)."},{"t":"example","text":"Неужéли = Tôi rất ngạc nhiên, tôi không thể tin được điều đó là sự thật (Thật ư...?/Chẳng lẽ lại...?). Неужели mang sắc thái cảm xúc mạnh hơn Разве."},{"t":"para","text":"1. Неужéли мóжно в такóй морóз ходúть в лéтней кýртке?","b":1},{"t":"para","text":"Dịch: Chẳng lẽ/Thật ư có thể mặc áo khoác mùa hè đi trong trời rét thế này sao? (Ngạc nhiên tột độ vì điều phi lý)."},{"t":"para","text":"2. ... ты не слы́шал э́то и́мя? -> Рáзве ты не слы́шал э́то и́мя?"},{"t":"para","text":"Dịch: Chẳng lẽ cậu chưa nghe cái tên này à? (Tôi tưởng cậu nghe rồi)."},{"t":"para","text":"3. ... он приезжáет в три часá? Я звонúл на вокзáл, и мне сказáли, что пóезд прихóдит в пять. -> Рáзве он приезжáет в три часá?"},{"t":"para","text":"Dịch: Chẳng lẽ anh ấy đến lúc 3 giờ sao? (Tôi có thông tin khác là 5 giờ, tôi nghi ngờ thông tin 3 giờ)."},{"t":"para","text":"4. ... ты э́то сдéлал? Как ты мог так поступúть! -> Неужéли ты э́то сдéлал?"},{"t":"para","text":"Dịch: Chẳng lẽ/Có thật là cậu đã làm điều này? Sao cậu có thể hành động như thế! (Sốc, không tin nổi)."},{"t":"para","text":"5. ... мóжно опáздывать на заня́тия? -> Неужéли (hoặc Разве) мóжно..."},{"t":"para","text":"Dịch: Chẳng lẽ lại có thể đi học muộn thế này sao? (Phê phán)."},{"t":"para","text":"6. ... ужé пять часóв? Как бы́стро летúт врéмя! -> Неужéли ужé пять часóв?"},{"t":"para","text":"Dịch: Đã 5 giờ rồi ư? Thời gian trôi nhanh quá! (Ngạc nhiên về thời gian)."},{"t":"para","text":"7. ... все присýтствующие знáют об э́том? Я, напримéр, слы́шу э́ту информáцию впервы́е. -> Рáзве все...? (hoặc Неужели)."},{"t":"para","text":"Dịch: Chẳng lẽ tất cả mọi người đều biết chuyện này? Ví dụ như tôi mới nghe lần đầu. (Nghi ngờ việc \"tất cả đều biết\")."},{"t":"para","text":"8. ... ты не читáл э́ту кнúгу? Онá есть в кáждой библиотéке. -> Рáзве ты не читáл...?"},{"t":"para","text":"Dịch: Chẳng lẽ cậu chưa đọc sách này? (Tôi nghĩ cậu phải đọc rồi chứ)."},{"t":"para","text":"9. ... он прóбудет у нас тóлько три дня? Как жаль. -> Неужéли (hoặc Разве)."},{"t":"para","text":"Dịch: Thật ư, anh ấy chỉ ở lại có 3 ngày thôi sao? Tiếc quá."},{"t":"para","text":"10. ... ты веришь томý, что он обмáнывал нас всё э́то врéмя? -> Неужéли ты веришь...?"},{"t":"para","text":"Dịch: Chẳng lẽ cậu tin rằng hắn đã lừa chúng ta suốt thời gian qua sao? (Khó tin)."},{"t":"para","text":"11. ... ты допускáешь, что онá э́то сдéлала нарóчно? -> Неужéли ты допускáешь...?"},{"t":"para","text":"Dịch: Cậu thực sự cho rằng cô ấy cố tình làm thế sao?"},{"t":"para","text":"12. ... он изучáет рýсский язы́к? Я почемý-то был увéрен в том, что он занимáется францýзским. -> Рáзве он изучáет...?"},{"t":"para","text":"Dịch: Chẳng lẽ cậu ấy học tiếng Nga à? Sao tôi cứ đinh ninh là cậu ấy học tiếng Pháp. (Nghi ngờ thông tin mới so với niềm tin cũ)."},{"t":"para","text":"13. ... мóжно подвергáть опáсности блúзких людéй? -> Неужéли мóжно...?"},{"t":"para","text":"Dịch: Chẳng lẽ lại có thể đẩy người thân vào nguy hiểm sao? (Phẫn nộ/Ngạc nhiên đạo đức)."},{"t":"para","text":"14. ... вы тóже отдыхáли в э́то врéмя в Палáнге? Как жаль, что мы с вáми не встрéтились! -> Рáзве (hoặc Неужели)."},{"t":"para","text":"Dịch: Thật à, các bạn cũng nghỉ ở Palanga lúc đó sao? Tiếc là không gặp nhau!"},{"t":"para","text":"15. ... э́тому дóму сто лет? В э́то трýдно повéрить. -> Неужéли э́тому дóму сто лет?"},{"t":"para","text":"Dịch: Ngôi nhà này 100 tuổi rồi thật ư? Khó tin quá."},{"t":"para","text":"16. ... концéрт отменúли? Óчень жаль. -> Рáзве / Неужели концéрт отменúли?"},{"t":"para","text":"Dịch: Buổi hòa nhạc bị hủy rồi sao? Tiếc quá."},{"t":"para","text":"17. ... тебé так трýдно вы́слушать меня́ до концá? -> Неужéли тебé так трýдно...?"},{"t":"para","text":"Dịch: Chẳng lẽ nghe tôi nói hết lời lại khó khăn với bạn đến thế sao? (Trách móc)."},{"t":"para","text":"18. ... мóжно оскорбля́ть человéка? -> Неужéли мóжно...?"},{"t":"para","text":"Dịch: Sao lại có thể xúc phạm người khác như thế?"},{"t":"para","text":"19. ... мы с вáми из одногó гóрода? Прия́тно встрéтить землякá вдалú от рóдины. -> Неужéли / Разве."},{"t":"para","text":"Dịch: Thật sao, chúng ta cùng quê à? Vui quá..."},{"t":"para","text":"20. ... справедлúво то, что кáждый день я дóлжен задéрживаться на рабóте до девяти́ часóв вéчера? -> Рáзве / Неужели справедлúво...?"},{"t":"para","text":"Dịch: Chẳng lẽ việc tôi ngày nào cũng phải ở lại làm đến 9 giờ tối là công bằng sao?"},{"t":"para","text":"21. ... музéй закры́т? Мы так хотéли попáсть на вы́ставку! -> Неужéли музéй закры́т?"},{"t":"para","text":"Dịch: Thật ư, bảo tàng đóng cửa rồi sao? Chúng tôi muốn xem triển lãm quá!"},{"t":"note","text":"Lưu ý chung cho học sinh:","b":1},{"t":"para","text":"Các bài tập này giúp các em cảm nhận sắc thái (nuance) của tiếng Nga."},{"t":"vocab","ru":"И́менно/Как рáз","vi":"И́менно giống như ngón tay chỉ thẳng vào vật (Cái này!), còn Как рáз giống như hai mảnh ghép khớp vào nhau (Vừa vặn/Đúng dịp).","g":null},{"t":"vocab","ru":"Рáзве/Неужéли","vi":"Рáзве là câu hỏi nghi vấn nhẹ (Tôi tưởng A, sao lại là B?), còn Неужéли là cảm xúc mạnh (Trời ơi! Không thể tin được là B!).","g":null},{"t":"para","text":"Chào em, đây là phần giải thích chi tiết, dịch thuật và hướng dẫn làm bài tập từ 492 đến 495 trong sách \"Грамматика русского языка в упражнениях и комментариях. Морфология\" (O. I. Glazunova), trang 246-248."},{"t":"para","text":"Trước khi làm bài, chúng ta cần nắm vững lý thuyết về các tiểu từ (частицы) đã học ở các phần trước và phần mới về đại từ bất định."}]},{"id":"06-s015","type":"exercise","title":"BÀI TẬP 492 (Trang 246)","num":492,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền các tiểu từ thích hợp theo ý nghĩa vào chỗ trống (Dựa vào ngữ cảnh để chọn các từ như: бы, ли, же, не, ни, ведь, ещё, уже, неужели, разве...)."},{"t":"para","text":"1. Я приéхал бы рáньше, но меня́ задержа́ли делá.","b":1},{"t":"para","text":"Dịch: Lẽ ra tôi đã đến sớm hơn, nhưng công việc đã giữ chân tôi lại."},{"t":"example","text":"Giải thích: Бы dùng để tạo thành câu điều kiện hoặc giả định (lẽ ra đã... nếu không...)."},{"t":"para","text":"2. — Вы хотúте поéхать в Сýздаль? — Ещё бы (hoặc Коне́чно), с удовóльствием.","b":1},{"t":"para","text":"Dịch: — Bạn có muốn đi Suzdal không? — Còn phải hỏi (Tất nhiên rồi), rất sẵn lòng."},{"t":"example","text":"Giải thích: Ещё бы là câu cảm thán mang nghĩa \"Đương nhiên rồi/Chắc chắn rồi\", thể hiện sự đồng ý nhiệt tình."},{"t":"para","text":"3. Неужéли (hoặc Рáзве) канúкулы ужé закóнчились?","b":1},{"t":"para","text":"Dịch: Chẳng lẽ/Thật ư kỳ nghỉ đã kết thúc rồi sao?"},{"t":"example","text":"Giải thích: Неужéли hoặc Рáзве dùng để hỏi với sắc thái ngạc nhiên hoặc nghi ngờ (tưởng là chưa hết)."},{"t":"para","text":"4. Давáйте пойдём по тротуáру, а не по дорóге, рáньше здéсь не бы́ло проблéм.","b":1},{"t":"para","text":"Dịch: Chúng ta hãy đi trên vỉa hè chứ đừng đi dưới lòng đường, trước đây ở đây không có vấn đề gì (nhưng giờ thì nguy hiểm)."},{"t":"example","text":"Giải thích: Dùng не để phủ định lựa chọn đi dưới lòng đường."},{"t":"para","text":"5. Бы́ли ли вы в Петропáвловской крéпости?","b":1},{"t":"para","text":"Dịch: Các bạn đã đến Pháo đài Peter và Paul chưa? (Có đến... không?)."},{"t":"example","text":"Giải thích: Ли là tiểu từ nghi vấn, đứng sau từ mang trọng tâm câu hỏi."},{"t":"para","text":"6. Что за (hoặc Ну и) ребёнок! Не умéет обращáться с ним ни однá ня́ня.","b":1},{"t":"para","text":"Dịch: Thật là một đứa trẻ (ghê gớm)! Không một bảo mẫu nào biết cách cư xử với nó."},{"t":"example","text":"Giải thích: Что за dùng để cảm thán về tính chất. Ни đi với одна để nhấn mạnh phủ định hoàn toàn (không một ai)."},{"t":"para","text":"7. Лишь бы (hoặc Тóлько бы) успéть на пóезд, всё остальнóе не вáжно.","b":1},{"t":"para","text":"Dịch: Miễn là/Giá mà kịp tàu, mọi thứ còn lại đều không quan trọng."},{"t":"example","text":"Giải thích: Лишь бы / Только бы diễn tả mong ước duy nhất hoặc điều kiện tối thiểu."},{"t":"para","text":"8. Пусть (hoặc Пускáй) в Нóвом годý испóлнятся все задýманные желáния.","b":1},{"t":"para","text":"Dịch: Cầu cho/Mong rằng trong Năm mới mọi mong ước đã định sẽ thành hiện thực."},{"t":"example","text":"Giải thích: Пусть dùng để tạo câu cầu khiến, chúc tụng ở ngôi thứ 3."},{"t":"para","text":"9. Хóчешь не хóчешь, а нáдо рабóтать.","b":1},{"t":"para","text":"Dịch: Dù muốn hay không (muốn), thì vẫn phải làm việc."},{"t":"example","text":"Giải thích: Cấu trúc Хочешь не хочешь (dù muốn dù không - bắt buộc)."},{"t":"para","text":"10. Смóжете ли вы брóсить моё письмó в почтóвый я́щик?","b":1},{"t":"para","text":"Dịch: Bạn có thể bỏ giúp tôi lá thư vào hòm thư được không?"},{"t":"example","text":"Giải thích: Ли dùng trong câu hỏi lịch sự hoặc nghi vấn."},{"t":"para","text":"11. Я бы был óчень рад помóчь вам.","b":1},{"t":"para","text":"Dịch: Tôi (lẽ ra sẽ) rất vui lòng được giúp bạn (nhưng có thể không giúp được hoặc đây là cách nói lịch sự)."},{"t":"example","text":"Giải thích: Бы thể hiện sự giả định hoặc lịch sự."},{"t":"para","text":"12. Мне не хватúло лишь (hoặc всегó) умá, чтóбы хорошó подготóвиться к экзáмену!","b":1},{"t":"para","text":"Dịch: Tôi chỉ thiếu một chút trí khôn để chuẩn bị tốt cho kỳ thi! (Ý tự trách)."},{"t":"example","text":"Giải thích: Лишь hoặc всего dùng để giới hạn."},{"t":"para","text":"13. В головé ни однóй мы́сли.","b":1},{"t":"para","text":"Dịch: Trong đầu chẳng có lấy một suy nghĩ nào."},{"t":"example","text":"Giải thích: Ни nhấn mạnh sự vắng mặt hoàn toàn (không một)."},{"t":"para","text":"14. Ты знáешь, я, ка́жется (hoặc вро́де), тaм никогдá не был. Или: я ещё там никогда не был.","b":1},{"t":"note","text":"Lưu ý: Sách đáp án gợi ý: Ты знаешь, я не готов... Как тебе не хватило (đây là đáp án cho câu khác hoặc sách in nhầm thứ tự)."},{"t":"example","text":"Sửa theo ngữ cảnh câu 14 thực tế: Ты знаешь, я ещё там никогда не был (Biết không, tớ vẫn chưa bao giờ đến đó). Hoặc: я ведь там... (tớ đã đến đó bao giờ đâu mà)."},{"t":"para","text":"15. Да бýдет вáша жизнь дóлгой и счастлúвой.","b":1},{"t":"para","text":"Dịch: Cầu cho cuộc sống của bạn lâu dài và hạnh phúc."},{"t":"example","text":"Giải thích: Да ở đầu câu cầu khiến mang nghĩa trang trọng (như \"Long live\")."},{"t":"para","text":"16. Что за (hoặc Ну и) мальчúшество, рáзве мóжно так поступáть взрóслому человéку!","b":1},{"t":"para","text":"Dịch: Trẻ con kiểu gì thế này, chẳng lẽ người lớn lại có thể hành xử như vậy sao!"},{"t":"example","text":"Giải thích: Что за (cảm thán chê trách), Разве (nghi vấn trách móc)."},{"t":"para","text":"17. Рáзве (hoặc Неужéли) мы с вáми не встречáлись рáньше?","b":1},{"t":"para","text":"Dịch: Chẳng lẽ chúng ta chưa từng gặp nhau trước đây sao?"},{"t":"para","text":"Giải thích: Câu hỏi nghi vấn phủ định đê xác nhận lại trí nhớ."}]},{"id":"06-s016","type":"exercise","title":"BÀI TẬP 493 (Trang 246)","num":493,"blocks":[{"t":"instruction","text":"Yêu cầu: Chọn các tiểu từ/cụm từ thích hợp thay thế cho các từ/cụm từ in nghiêng (hoặc bôi đậm) để tạo sắc thái biểu cảm tương đương."},{"t":"para","text":"1. Да, ситуáция слóжная, тóлько (hoặc вот) я не понимáю, в чём я виновáт.","b":1},{"t":"example","text":"Gốc: но я не понимаю (nhưng tôi không hiểu)."},{"t":"example","text":"Thay bằng: Только / Вот (Chỉ có điều là / Có điều là...)."},{"t":"para","text":"Dịch: Vâng, tình huống phức tạp đấy, chỉ có điều tôi không hiểu tôi có lỗi gì."},{"t":"para","text":"2. Удивúл ты нас, пря́мо (hoặc прóсто) фóкусник, да и тóлько.","b":1},{"t":"example","text":"Gốc: фокусник, да и только (đúng là ảo thuật gia)."},{"t":"example","text":"Thay bằng: Прямо / Просто (Cứ như là / Quả đúng là)."},{"t":"para","text":"Dịch: Cậu làm chúng tôi ngạc nhiên đấy, cứ như là ảo thuật gia vậy."},{"t":"para","text":"3. Я увéрен, у негó всё полýчится, он ведь спрáвился с э́тим задáнием в прóшлом годý.","b":1},{"t":"example","text":"Gốc: справился он... (anh ấy đã làm được...)."},{"t":"example","text":"Thay bằng: Ведь (Vì/Cơ mà - giải thích lý do hiển nhiên)."},{"t":"para","text":"Dịch: Tôi tin cậu ấy sẽ thành công, năm ngoái cậu ấy đã hoàn thành nhiệm vụ này rồi cơ mà."},{"t":"para","text":"4. — У тебя́ есть ключи́? — Врóде бы (hoặc Кáжется) я брал их с собóй, сейчáс посмотрю́.","b":1},{"t":"example","text":"Gốc: Я брал их... (Tôi đã cầm...)."},{"t":"example","text":"Thay bằng: Вроде бы (Hình như/Có vẻ là)."},{"t":"para","text":"Dịch: — Cậu có chìa khóa không? — Hình như tớ có cầm theo, để tớ xem đã."},{"t":"para","text":"5. Как (hoặc Лишь) тóлько мы приéхали на мóре, погóда испóртилась.","b":1},{"t":"example","text":"Gốc: Мы приехали... (Chúng tôi đến... thì...)."},{"t":"example","text":"Thay bằng: Как только / Лишь только (Ngay khi)."},{"t":"para","text":"Dịch: Ngay khi chúng tôi vừa đến biển thì thời tiết xấu đi."},{"t":"para","text":"6. Закóнчится ли э́то когдá-нибудь и́ли нет?","b":1},{"t":"example","text":"Gốc: Закончится это..."},{"t":"example","text":"Thay bằng: Thêm ли để nhấn mạnh sự nghi vấn/sốt ruột."},{"t":"para","text":"Dịch: Chuyện này liệu có bao giờ kết thúc hay không đây?"},{"t":"vocab","ru":"Лýчше не садúсь с ним игрáть в шáхматы","vi":"он всё равнó (hoặc так и так) у тебя́ вы́играет.","g":null},{"t":"example","text":"Gốc: он все равно..."},{"t":"example","text":"Thay bằng: Giữ nguyên hoặc dùng всё же (rốt cuộc thì)."},{"t":"para","text":"Dịch: Tốt nhất đừng ngồi chơi cờ với hắn: đằng nào hắn cũng thắng cậu thôi."},{"t":"para","text":"8. Я всё (hoặc как рáз) дýмаю, что нам нáдо предприня́ть для тогó, чтóбы победúть.","b":1},{"t":"example","text":"Gốc: Я думаю..."},{"t":"example","text":"Thay bằng: Всё (Vẫn cứ/Mãi)."},{"t":"para","text":"Dịch: Tôi vẫn cứ đang suy nghĩ xem chúng ta cần làm gì để chiến thắng."},{"t":"vocab","ru":"Весь мéсяц не бы́ло дождéй","vi":"тогó и гляди́ (hoặc не ровён час) урожáй пропадёт.","g":null},{"t":"example","text":"Gốc: урожай пропадет (mùa màng sẽ mất)."},{"t":"example","text":"Thay bằng: Того и гляди (Coi chừng/Khéo mà - lo ngại điều sắp xảy ra)."},{"t":"para","text":"Dịch: Cả tháng không mưa: khéo mà mất mùa mất thôi."},{"t":"para","text":"10. Э́то слóжный вопрóс, дáже преподавáтель не смог на негó срáзу отвéтить.","b":1},{"t":"example","text":"Gốc: преподаватель не смог..."},{"t":"example","text":"Thay bằng: Даже (Thậm chí)."},{"t":"para","text":"Dịch: Câu hỏi khó đấy, ngay cả/thậm chí giáo viên cũng không trả lời ngay được."},{"t":"para","text":"11. — Ты придёшь на вéчер? — Ещё бы! (hoặc А то как же!).","b":1},{"t":"example","text":"Gốc: С удовольствием (Rất sẵn lòng)."},{"t":"example","text":"Thay bằng: Ещё бы (Còn phải hỏi/Tất nhiên)."},{"t":"para","text":"Dịch: — Cậu đến dự tiệc chứ? — Tất nhiên rồi!"},{"t":"para","text":"12. — Мы пойдём пешкóм. — Но ведь идтú придётся часá два, не мéньше.","b":1},{"t":"example","text":"Gốc: Но идти придется..."},{"t":"example","text":"Thay bằng: Но ведь (Nhưng mà... cơ mà)."},{"t":"para","text":"Dịch: — Chúng tớ đi bộ. — Nhưng mà sẽ phải đi mất 2 tiếng đấy, không ít đâu."},{"t":"para","text":"13. Пусть (hoặc Пускáй) он вы́моет посýду, сегóдня егó óчередь.","b":1},{"t":"example","text":"Gốc: Он вымоет... (Cậu ấy sẽ rửa...)."},{"t":"example","text":"Thay bằng: Пусть (Hãy để/Bắt)."},{"t":"para","text":"Dịch: Hãy để/Bắt cậu ấy rửa bát, hôm nay đến lượt cậu ấy."},{"t":"para","text":"14. Я едвá (hoặc чуть) не забýл об экзáмене, хорошó, что ты позвонúл и напóмнил.","b":1},{"t":"example","text":"Gốc: Я забыл... (Tôi quên... - ý là suýt quên)."},{"t":"example","text":"Thay bằng: Едва не / Чуть не (Suýt nữa thì)."},{"t":"para","text":"Dịch: Tôi suýt nữa thì quên kỳ thi, may mà cậu gọi nhắc."},{"t":"para","text":"15. Мы с ним так дóлго не вúделись, я прóсто (hoặc дáже) забýл, как он вы́глядит.","b":1},{"t":"example","text":"Gốc: я забыл..."},{"t":"example","text":"Thay bằng: Просто / Даже (Quả thực là/Thậm chí)."},{"t":"para","text":"Dịch: Chúng tôi không gặp nhau lâu quá, tôi thậm chí/quả tình đã quên mặt anh ấy rồi."},{"t":"para","text":"16. Рáзве (hoặc Неужéли) он не бýдет сдавáть экзáмен?","b":1},{"t":"example","text":"Gốc: Он не будет...?"},{"t":"example","text":"Thay bằng: Разве / Неужели (Chẳng lẽ...)."},{"t":"para","text":"Dịch: Chẳng lẽ cậu ấy không thi sao?"},{"t":"para","text":"17. Э́то необы́чная ситуáция, я прóсто (hoặc пря́мо) не знáю, что предприня́ть.","b":1},{"t":"example","text":"Gốc: я не знаю..."},{"t":"example","text":"Thay bằng: Просто / Прямо (Hoàn toàn/Thực sự)."},{"t":"para","text":"Dịch: Tình huống này lạ quá, tôi thực sự không biết phải làm gì."},{"t":"para","text":"18. И́менно (hoặc Как рáз) зáвтра всё и должнó произойтú.","b":1},{"t":"example","text":"Gốc: Завтра..."},{"t":"example","text":"Thay bằng: Именно / Как раз (Chính/Đúng)."},{"t":"para","text":"Dịch: Chính ngày mai mọi chuyện sẽ phải xảy ra."},{"t":"para","text":"19. Он далекó (hoặc вовсе) не глуп.","b":1},{"t":"example","text":"Gốc: Он не глуп."},{"t":"example","text":"Thay bằng: Далеко не / Вовсе не (Chẳng... chút nào/Hoàn toàn không)."},{"t":"para","text":"Dịch: Cậu ta chẳng ngốc chút nào đâu."},{"t":"para","text":"20. Я как рáз (hoặc же) с вáми не соглáсен.","b":1},{"t":"example","text":"Gốc: Я с вами не согласен."},{"t":"example","text":"Thay bằng: Как раз (Chính là/Lại - ý phản bác)."},{"t":"para","text":"Dịch: Tôi lại/chính là không đồng ý với các bạn."}]},{"id":"06-s017","type":"grammar","title":"PHẦN NGỮ PHÁP (Trang 247)","num":null,"blocks":[{"t":"subhead","text":"Đại từ bất định (Неопределённые местоимения):","b":1},{"t":"vocab","ru":"-то (кто-то, где-то)","vi":"Dùng khi người nói biết sự việc đã xảy ra hoặc đối tượng có thật, nhưng không biết chính xác hoặc khó nhớ lại (quá khứ/hiện tại). Nghĩa: ...nào đó.","g":null},{"t":"vocab","ru":"-нибудь / -либо (кто-нибудь, где-нибудь)","vi":"Dùng khi người nói không quan tâm đó là ai/cái gì, hoặc dùng trong câu hỏi, câu cầu khiến, tương lai, giả định. Nghĩa: ...bất cứ ... nào / ...gì đó.","g":null},{"t":"vocab","ru":"кое- (кое-кто, кое-где)","vi":"Dùng khi người nói biết rõ đối tượng nhưng không muốn nói ra (bí mật hoặc tế nhị). Nghĩa: một vài..., ...nọ.","g":null}]},{"id":"06-s018","type":"exercise","title":"BÀI TẬP 494 (Trang 247)","num":494,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu văn. Xác định sự khác biệt về ý nghĩa của các tiểu từ (hậu tố/tiền tố tạo đại từ) -то, -нибудь, кое-."},{"t":"para","text":"a) Nhóm dùng \"-то\" (Cụ thể nhưng không rõ danh tính/đã xảy ra)","b":1},{"t":"example","text":"Кто-то постучал в дверь... (Có ai đó đã gõ cửa - Có người gõ thật, nhưng không biết ai)."},{"t":"example","text":"Я знал, что что-то должно произойти. (Tôi biết là chuyện gì đó phải xảy ra - Chuyện cụ thể)."},{"t":"example","text":"Этот цвет какой-то неопределенный... (Màu này thế nào ấy, không rõ ràng - Một màu cụ thể trước mắt nhưng khó tả)."},{"t":"example","text":"Вчера я нашел... чей-то учебник. (Hôm qua tôi tìm thấy sách của ai đó - Của một người cụ thể nào đó)."},{"t":"example","text":"Аптека находится где-то недалеко... (Hiệu thuốc nằm ở đâu đó gần đây - Có địa điểm thật, chỉ là tôi không nhớ chính xác)."},{"t":"example","text":"Он приехал откуда-то издалека. (Anh ấy đến từ đâu đó xa xôi)."},{"t":"example","text":"Когда-то давно... (Hồi xưa/Lâu lắm rồi... - Một thời điểm trong quá khứ)."},{"t":"example","text":"Всё произошло как-то само собой... (Mọi chuyện xảy ra cứ thế nào ấy, tự nhiên...)."},{"t":"example","text":"Никто... не говорил, но он почему-то встал и вышел. (Không ai nói gì, nhưng vì lý do nào đó anh ấy đứng dậy và đi ra - Có lý do, người nói không biết)."},{"t":"para","text":"б) Nhóm dùng \"-нибудь\" (Bất định, bất kỳ, tương lai, câu hỏi)","b":1},{"t":"example","text":"Кто-нибудь может мне помочь? (Có ai [bất kỳ ai] có thể giúp tôi không? - Câu hỏi/Yêu cầu)."},{"t":"example","text":"Я что-нибудь хочу почитать. (Tôi muốn đọc cái gì đó - Quyển nào cũng được)."},{"t":"example","text":"Обязательно должен быть какой-нибудь выход... (Chắc chắn phải có một lối thoát nào đó - Chưa tìm ra, hy vọng là có)."},{"t":"example","text":"Мне нужна чья-нибудь помощь. (Tôi cần sự giúp đỡ của ai đó - Ai cũng được)."},{"t":"example","text":"Мы можем завтра встретиться где-нибудь...? (Mai chúng ta gặp nhau ở đâu đó được không? - Chưa chốt địa điểm)."},{"t":"example","text":"Откуда я узнаю...? — Узнаешь откуда-нибудь... (Làm sao tôi biết? - Thì tìm nguồn nào đó mà biết - Nguồn nào cũng được)."},{"t":"example","text":"...когда-нибудь ты обязательно выиграешь... (Lúc nào đó [trong tương lai] bạn nhất định sẽ thắng)."},{"t":"example","text":"Останьтесь... — Спасибо, как-нибудь в другой раз. (Cảm ơn, để khi khác/dịp nào đó nhé - Từ chối khéo, thời gian không xác định)."},{"t":"para","text":"в) Nhóm dùng \"кое-\" (Biết rõ nhưng không nói)","b":1},{"t":"example","text":"Кое-кого я уже попросил... (Tôi đã nhờ một vài người rồi - Tôi biết là ai, nhưng không tiện nói tên)."},{"t":"example","text":"Кое-что я могу тебе сообщить. (Tôi có thể báo cho bạn vài điều - Thông tin cụ thể tôi đang giữ)."},{"t":"example","text":"Кое-какая информация... (Một vài thông tin...)."},{"t":"example","text":"Кое-чья поддержка... (Sự ủng hộ của một người nọ...)."},{"t":"example","text":"Кое-где... (Ở một vài nơi...)."},{"t":"example","text":"Мы часто задерживались... кое-когда приходилось... (Chúng tôi thường ở lại muộn... thi thoảng [có những lúc cụ thể] phải về nhà lúc đêm sâu)."},{"t":"example","text":"одет кое-как... (Ăn mặc xuề xòa/qua loa - Cấu trúc кое-как thường mang nghĩa tiêu cực: làm cho có, cẩu thả)."}]},{"id":"06-s019","type":"exercise","title":"BÀI TẬP 495 (Trang 248)","num":495,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng hình thức đúng của đại từ/trạng từ với -то, -нибудь, кое-."},{"t":"example","text":"Nguyên tắc:"},{"t":"para","text":"Quá khứ, hiện tại cụ thể, \"một cái nào đó\" -> -то."},{"t":"para","text":"Tương lai, câu hỏi, \"bất kỳ cái nào\", cầu khiến -> -нибудь."},{"t":"para","text":"Biết mà giấu -> кое-."},{"t":"para","text":"1. Дай мне почитать (какую) каку́ю-нибудь книгу.","b":1},{"t":"para","text":"Dịch: Đưa tớ đọc cuốn sách nào đó đi (quyển nào cũng được)."},{"t":"para","text":"Giải thích: Yêu cầu, đối tượng không xác định cụ thể."},{"t":"para","text":"2. Он давно не звонил мне, наверное, (что) чтó-то случилось.","b":1},{"t":"para","text":"Dịch: Lâu rồi cậu ấy không gọi, chắc là đã xảy ra chuyện gì đó."},{"t":"para","text":"Giải thích: Phỏng đoán về một sự việc có thật trong quá khứ/hiện tại."},{"t":"para","text":"3. Расскажи мне (какой) какóй-нибудь смешной эпизод из твоей жизни.","b":1},{"t":"para","text":"Dịch: Kể cho tớ nghe một đoạn hài hước nào đó trong đời cậu đi."},{"t":"para","text":"Giải thích: Yêu cầu kể một chuyện bất kỳ."},{"t":"para","text":"4. Он приехал (откуда) откýда-то с Севера.","b":1},{"t":"para","text":"Dịch: Anh ấy đến từ đâu đó miền Bắc (Tôi biết là miền Bắc nhưng không rõ thành phố nào)."},{"t":"para","text":"Giải thích: Sự việc thực tế, người nói không biết rõ chi tiết."},{"t":"para","text":"5. Мы оставили его, (где) гдé-то в районе Сенной площади.","b":1},{"t":"para","text":"Dịch: Chúng tôi đã để anh ấy lại ở đâu đó khu Quảng trường Sennaya."},{"t":"para","text":"Giải thích: Địa điểm có thật trong quá khứ, không nhớ chính xác."},{"t":"para","text":"6. (Когда) Когдá-то (hoặc Порой) у меня выпадает свободное время, но не очень часто.","b":1},{"t":"note","text":"Lưu ý: Văn cảnh này \"Có những lúc tôi có thời gian rảnh\". Dùng когда-то thường chỉ quá khứ xa. Nếu chỉ tần suất \"Thỉnh thoảng\", tiếng Nga hay dùng иногда / порой. Nếu bắt buộc dùng nhóm từ này:"},{"t":"subhead","text":"Đáp án: Кое-когда́ (Thi thoảng/Đôi khi - biết là có những lúc đó). Hoặc nếu ý là \"Ngày xưa tôi có thời gian\" -> Когда́-то."},{"t":"example","text":"Sách đáp án (nếu theo key 495.6): когда́-то (Ý nói trước đây/hồi xưa thì có, giờ thì ít)."},{"t":"para","text":"7. Давай встретимся (где) гдé-нибудь по дороге в университет.","b":1},{"t":"para","text":"Dịch: Chúng ta hãy gặp nhau ở chỗ nào đó trên đường đến trường nhé."},{"t":"para","text":"Giải thích: Lời rủ rê, địa điểm chưa chốt (bất kỳ chỗ nào tiện)."},{"t":"para","text":"8. (Где), то там, то тут, собирались группы людей. -> Кое-гдé."},{"t":"para","text":"Dịch: Rải rác đây đó (vài chỗ), chỗ này chỗ kia, từng nhóm người tụ tập."},{"t":"para","text":"Giải thích: Liệt kê các địa điểm cụ thể rải rác."},{"t":"para","text":"9. Я должен передать эту книгу (какой) какóму-то (hoặc какóму-нибудь) конкретному человеку?","b":1},{"t":"para","text":"Dịch: Tôi phải đưa sách này cho một người cụ thể nào đó à?"},{"t":"example","text":"Giải thích: Nếu hỏi về sự tồn tại của một người cụ thể mà người nói không biết -> какому-то. Nếu hỏi \"bất kỳ ai cụ thể\" -> какому-нибудь. Ngữ cảnh này какому-то (người đó là ai thế?) hợp lý hơn."},{"t":"para","text":"10. Вчера о тебе (кто) ктó-то спрашивал, он сказал, что учился с тобой в университете.","b":1},{"t":"para","text":"Dịch: Hôm qua có ai đó hỏi về bạn, hắn nói là học cùng đại học với bạn."},{"t":"para","text":"Giải thích: Người cụ thể đã xuất hiện trong quá khứ."},{"t":"para","text":"11. Я очень хочу уехать (куда) кудá-нибудь на юг отдохнуть.","b":1},{"t":"para","text":"Dịch: Tôi rất muốn đi đâu đó về phía Nam nghỉ ngơi."},{"t":"para","text":"Giải thích: Mong muốn, địa điểm chưa xác định (miễn là phía Nam)."},{"t":"para","text":"12. — (Что) Чтó-то случилось? — Да, (что) кóе-что произошло!","b":1},{"t":"para","text":"Dịch: — Có chuyện gì xảy ra à? — Ừ, có chuyện này (hay lắm/quan trọng lắm) đã xảy ra!"},{"t":"example","text":"Giải thích: Что-то (hỏi về sự việc không rõ), Кое-что (người trả lời biết rõ và sắp kể hoặc giữ bí mật mức độ quan trọng)."},{"t":"para","text":"13. Мне нужен (чей) чéй-нибудь учебник до завтра.","b":1},{"t":"para","text":"Dịch: Tớ cần sách giáo khoa của ai đó (ai cũng được) đến mai."},{"t":"para","text":"Giải thích: Cần bất kỳ cái nào."},{"t":"para","text":"14. В воскресенье мы с тобой (куда) кудá-нибудь поедем.","b":1},{"t":"para","text":"Dịch: Chủ nhật tớ với cậu sẽ đi đâu đó chơi."},{"t":"para","text":"Giải thích: Tương lai, dự định chưa chốt địa điểm."},{"t":"para","text":"15. Проходи, садись к столу, я для тебя (что) кóе-что приготовил!","b":1},{"t":"para","text":"Dịch: Vào đi, ngồi xuống bàn đi, tớ đã chuẩn bị cho cậu cái này (hay lắm)!"},{"t":"para","text":"Giải thích: Một món cụ thể, muốn gây bất ngờ."},{"t":"para","text":"16. Нельзя сидеть целый день дома, (куда) кудá-нибудь надо сходить погулять.","b":1},{"t":"para","text":"Dịch: Không thể ngồi nhà cả ngày được, phải đi đâu đó dạo chơi chứ."},{"t":"para","text":"Giải thích: Khuyên bảo, địa điểm bất kỳ."},{"t":"para","text":"17. Сегодня он получил (какой) какóе-то важное письмо и хотел с тобой посоветоваться.","b":1},{"t":"para","text":"Dịch: Hôm nay anh ấy nhận được một lá thư quan trọng nào đó và muốn hỏi ý kiến bạn."},{"t":"para","text":"Giải thích: Sự kiện có thật, lá thư cụ thể."},{"t":"vocab","ru":"Я доволен всеми своими учениками","vi":"(кто) ктó-то больше, (кто) ктó-то меньше.","g":null},{"t":"para","text":"Dịch: Tôi hài lòng với tất cả học sinh: người thì nhiều, người thì ít."},{"t":"example","text":"Giải thích: Dùng кто-то... кто-то để liệt kê phân bố."},{"t":"para","text":"19. Вы можете мне предоставить (какой) каки́е-нибудь гарантии того, что вы меня не подведёте?","b":1},{"t":"para","text":"Dịch: Các ngài có thể đưa ra cho tôi bất cứ sự đảm bảo nào... không?"},{"t":"para","text":"Giải thích: Câu hỏi, yêu cầu điều kiện."},{"t":"para","text":"20. По-моему, у него были (какой) каки́е-то проблемы с визой.","b":1},{"t":"para","text":"Dịch: Theo tôi, anh ấy đã gặp những vấn đề nào đó về visa."},{"t":"para","text":"Giải thích: Sự việc có thật trong quá khứ, người nói không rõ chi tiết vấn đề là gì."},{"t":"para","text":"Chào em, đây là phần giải thích chi tiết, dịch thuật và hướng dẫn làm bài tập từ 496 đến 500 trong sách \"Грамматика русского языка в упражнениях и комментариях. Морфология\" (O. I. Glazunova), trang 248-252."},{"t":"subhead","text":"Chủ đề chính của phần này là Đại từ bất định (Неопределённые местоимения) với các tiểu từ (hậu tố/tiền tố) -то, -нибудь, кое-, -либо và ôn tập tổng hợp về Tiểu từ."}]},{"id":"06-s020","type":"exercise","title":"BÀI TẬP 496 (Trang 248)","num":496,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng hình thức đúng của đại từ với -то, -нибудь hoặc кое- đi kèm giới từ."},{"t":"subhead","text":"Gợi ý ngữ pháp quan trọng:","b":1},{"t":"subhead","text":"Quy tắc vị trí giới từ với \"кое-\": Khi đại từ bất định bắt đầu bằng кое- đi kèm với giới từ, thì giới từ sẽ đứng Ở GIỮA."},{"t":"subhead","text":"Cấu trúc: кое + giới từ + đại từ"},{"t":"example","text":"Ví dụ: кое-кто (ai đó) + с (với) → кое с кем (với ai đó), chứ KHÔNG phải с кое-кем."},{"t":"vocab","ru":"Với -то và -нибудь, giới từ đứng trước như bình thường","vi":"с кем-то, с кем-нибудь.","g":null},{"t":"para","text":"1. Я хочу́ тебя́ (кто) с кем-то познако́мить.","b":1},{"t":"para","text":"Dịch: Tớ muốn giới thiệu cậu với một người nào đó (cụ thể)."},{"t":"example","text":"Giải thích: Người nói biết rõ người mình định giới thiệu là ai → dùng -то. Giới từ с đi với cách 5 (Т.п.)."},{"t":"example","text":"2. Он пришёл (какой) с како́й-то стра́нной молоды́м челове́ком. (Lưu ý: Sách gốc in nhầm молодым человеком là cách 5, nhưng странной lại là giống cái cách 5? Có thể sách định viết с какой-то странной девушкой hoặc с каким-то странным.... Giả sử theo молодым человеком thì phải là giống đực)."},{"t":"example","text":"Sửa lại cho đúng ngữ pháp: с каки́м-то стра́нным молоды́м челове́ком."},{"t":"para","text":"Dịch: Anh ấy đến cùng với một gã thanh niên lạ lùng nào đó."},{"t":"para","text":"Giải thích: Người nói thấy người đó nhưng không biết là ai → dùng -то."},{"t":"para","text":"3. Неуже́ли ты мо́жешь его́ (что) в чём-то упрекну́ть?","b":1},{"t":"para","text":"Dịch: Chẳng lẽ cậu có thể trách móc anh ấy về điều gì đó (cụ thể) sao?"},{"t":"example","text":"Giải thích: Giới từ в (về) + cách 6 (П.п.). Sự việc trách móc được coi là có thật/cụ thể → dùng -то."},{"t":"para","text":"4. На́до призна́ть, что (что) в чём-то ты прав.","b":1},{"t":"para","text":"Dịch: Phải thừa nhận rằng, ở điểm nào đó (trong chuyện này) thì cậu đúng."},{"t":"para","text":"Giải thích: Xác nhận một phần sự thật cụ thể → dùng -то."},{"t":"para","text":"5. Тебе́ обяза́тельно на́до (кто) с ке́м-нибудь спроси́ть сове́та.","b":1},{"t":"para","text":"Dịch: Cậu nhất định cần phải hỏi lời khuyên từ ai đó (bất kỳ ai biết việc)."},{"t":"example","text":"Giải thích: Lời khuyên cho tương lai, không chỉ định người cụ thể → dùng -нибудь. (Cấu trúc: спросить совета у кого hoặc посоветоваться с кем - Ở đây câu gốc dùng спросить nhưng lại yêu cầu điền кто với ý с кем là hơi lạ, thường là посоветоваться с кем. Nếu giữ спросить, có thể ý sách là посоветоваться с кем-нибудь)."},{"t":"note","text":"Lưu ý: Nếu sách dùng спросить thì đúng ra phải là у кого-нибудь. Nhưng nếu bắt buộc điền theo ngoặc (кто) để hợp với ngữ cảnh \"hỏi ý kiến\" (consult) thì thường dùng посоветоваться с кем-нибудь."},{"t":"subhead","text":"Đáp án sách (nếu theo key 496.5): с ке́м-нибудь (hiểu theo nghĩa посоветоваться)."},{"t":"para","text":"6. (Какой) С каки́ми-то докуме́нтами я уже́ ознако́мился.","b":1},{"t":"para","text":"Dịch: Tôi đã làm quen/xem qua một vài tài liệu nào đó rồi."},{"t":"para","text":"Giải thích: Hành động đã xảy ra, tài liệu cụ thể → dùng -то."},{"t":"para","text":"7. Дава́йте остано́вимся (какой) на како́м-нибудь одно́м вариа́нте.","b":1},{"t":"para","text":"Dịch: Chúng ta hãy dừng lại (chốt) ở bất kỳ phương án nào (một phương án thôi)."},{"t":"para","text":"Giải thích: Lời đề nghị cho tương lai, chọn cái nào cũng được miễn là chốt → dùng -нибудь."},{"t":"para","text":"8. (Кто) Кому́-то э́то мо́жет быть уда́чным стече́нием обстоя́тельств, но мне всегда́ ну́жно бо́льше.","b":1},{"t":"para","text":"Dịch: Với ai đó (người nào đó cụ thể) thì đây có thể là sự trùng hợp may mắn, nhưng với tôi thì luôn cần nhiều hơn thế."},{"t":"para","text":"Giải thích: So sánh với một đối tượng cụ thể trong suy nghĩ → dùng -то."},{"t":"para","text":"9. Они́ взя́ли биле́ты (какой) на како́й-то ближа́йший рейс, ка́жется, до Берли́на.","b":1},{"t":"para","text":"Dịch: Họ đã mua vé cho một chuyến bay gần nhất nào đó, hình như là tới Berlin."},{"t":"para","text":"Giải thích: Sự việc đã xảy ra, chuyến bay cụ thể nhưng người nói không nhớ rõ → dùng -то."},{"t":"para","text":"10. Вы (что) с чем-то не согла́сны? У вас есть (какой) каки́е-то preténzii?","b":1},{"t":"para","text":"Dịch: Các bạn không đồng ý với điều gì đó phải không? Các bạn có khiếu nại gì đó à?"},{"t":"para","text":"Giải thích: Hỏi về sự việc đang hiện hữu thực tế → dùng -то."},{"t":"para","text":"11. Извини́, я оста́влю тебя́ на мину́ту, мне на́до (кто) кое с кем поговори́ть.","b":1},{"t":"para","text":"Dịch: Xin lỗi, tớ để cậu lại một phút nhé, tớ cần nói chuyện với người này một chút (biết là ai nhưng không tiện nói tên với cậu)."},{"t":"example","text":"Giải thích: Người nói biết rõ đối tượng, giữ bí mật/tế nhị → dùng кое-. Giới từ с chèn vào giữa: кое с кем."},{"t":"para","text":"12. Ты был (кто) у кого́-нибудь из свои́х друзе́й?","b":1},{"t":"para","text":"Dịch: Cậu đã ghé qua chỗ ai đó/bất kỳ ai trong số bạn bè của cậu chưa?"},{"t":"para","text":"Giải thích: Câu hỏi nghi vấn chung chung → dùng -нибудь."},{"t":"para","text":"13. Э́тот пода́рок я пригото́вил (кто) для кого́-то из на́ших о́бщих знако́мых.","b":1},{"t":"para","text":"Dịch: Món quà này tớ đã chuẩn bị cho một người nào đó trong số người quen chung của chúng ta."},{"t":"para","text":"Giải thích: Người nói biết tỏng là ai, nhưng đang đố người nghe hoặc giữ bí mật → dùng -то (cụ thể) hoặc кое для кого (bí mật). Trong ngữ cảnh \"đố\" này, кое для кого hay hơn, nhưng для кого-то cũng đúng (cho một người cụ thể)."},{"t":"para","text":"14. Заходи́л Илья́, он хоте́л тебе́ сообщи́ть (что) чтó-то ва́жное.","b":1},{"t":"para","text":"Dịch: Ilya đã ghé qua, cậu ấy muốn báo cho bạn điều gì đó quan trọng."},{"t":"para","text":"Giải thích: Thông tin cụ thể → dùng -то."},{"t":"para","text":"15. Мне на́до ещё поду́мать (какой) над каки́ми-то (hoặc над ко́е-каки́ми) вопро́сами.","b":1},{"t":"para","text":"Dịch: Tôi cần suy nghĩ thêm về một vài vấn đề nào đó."},{"t":"para","text":"Giải thích: Vấn đề cụ thể. Nếu muốn nói \"vài vấn đề tôi biết nhưng không nói ra\" → над ко́е-каки́ми. Nếu chỉ là chung chung \"mấy vấn đề\" → над каки́ми-то."},{"t":"para","text":"16. (Какой) Каки́м-то твои́м иде́ям мы смогли́ найти́ примене́ние.","b":1},{"t":"para","text":"Dịch: Chúng tôi đã tìm được ứng dụng cho một số ý tưởng nào đó của bạn."},{"t":"para","text":"Giải thích: Ý tưởng cụ thể đã được chọn → dùng -то."},{"t":"para","text":"17. Дава́й зае́дем (кто) к кому́-нибудь по доро́ге домо́й, наприме́р, к на́шим о́бщим знако́мым из Ки́ева, что́бы расска́зать о случи́вшемся.","b":1},{"t":"para","text":"Dịch: Chúng ta hãy ghé qua chỗ ai đó trên đường về nhà đi, ví dụ như người quen chung ở Kiev..."},{"t":"para","text":"Giải thích: Lời rủ rê, đề xuất (chưa chốt chắc chắn là ai, chỉ là gợi ý) → dùng -нибудь."},{"t":"para","text":"18. (Кто) Кому́-то э́то пока́жется о́чень интере́сным, но мне ваш план не нра́вится.","b":1},{"t":"para","text":"Dịch: Với ai đó (người nào đó) thì điều này có vẻ thú vị, nhưng tôi thì không thích kế hoạch của bạn."},{"t":"para","text":"Giải thích: Đối tượng cụ thể trong suy nghĩ (người khác) → dùng -то."},{"t":"para","text":"19. Извини́те, я до́лжен идти́, мне ещё на́до (что) кое-чтó (hoặc чтó-то) поду́мать.","b":1},{"t":"example","text":"Sửa lại động từ: Câu gốc là \"надо ... подумать\" thì không cần tân ngữ trực tiếp (đại từ không cách). Có lẽ ý là сделать (làm) hoặc обдумать (suy nghĩ về)."},{"t":"example","text":"Giả sử là \"làm cái gì đó\": кое-чтó сде́лать."},{"t":"subhead","text":"Giả sử là \"mua cái gì đó\" (подумать -> купить?):"},{"t":"example","text":"Theo ngữ cảnh: \"Tôi phải đi, tôi còn phải (làm) việc này/chuyện này\". Người nói biết rõ việc gì → dùng ко́е-что."}]},{"id":"06-s021","type":"exercise","title":"BÀI TẬP 497 (Trang 249)","num":497,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng -нибудь hoặc -либо. Giải thích sự lựa chọn."},{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 249):","b":1},{"t":"vocab","ru":"-нибудь","vi":"Dùng trong văn nói và văn viết thông thường.","g":null},{"t":"vocab","ru":"-либо","vi":"Đồng nghĩa với -нибудь nhưng mang sắc thái trang trọng, văn phong hành chính - công vụ (официально-деловой стиль). Nghĩa là \"bất cứ... nào\".","g":null},{"t":"para","text":"1. У вас есть (какой)-либо прете́нзии к на́шей рабо́те?","b":1},{"t":"para","text":"Dịch: Các ông có khiếu nại nào về công việc của chúng tôi không?"},{"t":"para","text":"Giải thích: Văn phong hành chính/dịch vụ → dùng -либо."},{"t":"para","text":"2. На́до (кто)-нибудь посла́ть за хле́бом.","b":1},{"t":"para","text":"Dịch: Phải cử ai đó đi mua bánh mì thôi."},{"t":"para","text":"Giải thích: Văn nói sinh hoạt hàng ngày → dùng -нибудь."},{"t":"para","text":"3. Мо́жет быть, (кто)-либо из прису́тствующих хо́чет зада́ть вопро́с?","b":1},{"t":"para","text":"Dịch: Có lẽ, có vị nào trong số những người có mặt muốn đặt câu hỏi không?"},{"t":"example","text":"Giải thích: Văn phong hội nghị, trang trọng → dùng -либо (hoặc -нибудь cũng được, nhưng -либо lịch sự hơn)."},{"t":"para","text":"4. Е́сли вам ста́нет изве́стно (что)-либо но́вое по э́тому вопро́су, пожа́луйства, да́йте мне знать.","b":1},{"t":"para","text":"Dịch: Nếu ngài biết thêm bất cứ điều gì mới về vấn đề này, vui lòng báo cho tôi."},{"t":"para","text":"Giải thích: Văn phong trang trọng/công việc → dùng -либо."},{"t":"para","text":"5. (Кто)-нибудь хо́чет моро́женого?","b":1},{"t":"para","text":"Dịch: Có ai muốn ăn kem không?"},{"t":"para","text":"Giải thích: Văn nói thân mật → dùng -нибудь."},{"t":"example","text":"6. ...серьёзных попра́вок к прое́кту никто́ не сде́лал. (Câu này không có chỗ trống để điền что, có thể là câu dẫn)."},{"t":"para","text":"7. Ты (что)-нибудь слы́шишь?","b":1},{"t":"para","text":"Dịch: Cậu có nghe thấy gì không?"},{"t":"para","text":"Giải thích: Văn nói → dùng -нибудь."},{"t":"para","text":"8. Ты не мо́жешь жить споко́йно, тебе́ всегда́ (что)-то не хвата́ет.","b":1},{"t":"para","text":"Dịch: Cậu không thể sống yên ổn được, cậu luôn thiếu thốn cái gì đó (cụ thể)."},{"t":"note","text":"Lưu ý: Ở đây dùng -то (vì всегда ám chỉ thực tế lặp lại), hoặc чего́-нибудь (bất cứ cái gì). Ngữ cảnh này thường là чего-то. Nếu bắt buộc нибудь/либо → чего́-нибудь."},{"t":"para","text":"9. Е́сли в програ́мме произойду́т (какой)-либо измене́ния, мы обяза́тельно сообщи́м вам об э́том.","b":1},{"t":"para","text":"Dịch: Nếu có bất kỳ thay đổi nào trong chương trình, chúng tôi bắt buộc sẽ thông báo."},{"t":"para","text":"Giải thích: Thông báo chính thức → dùng -либо."},{"t":"para","text":"10. Вы (что)-нибудь забы́ли?","b":1},{"t":"para","text":"Dịch: Các bạn có quên gì không?"},{"t":"para","text":"Giải thích: Văn nói → dùng -нибудь."},{"t":"para","text":"11. Е́сли у вас бу́дут (какой)-либо (hoặc каки́е-нибудь) замеча́ния, позвони́те мне.","b":1},{"t":"para","text":"Dịch: Nếu các bạn có bất cứ nhận xét nào, hãy gọi cho tôi."},{"t":"example","text":"Giải thích: Cả hai đều được, -либо trang trọng hơn."},{"t":"para","text":"12. (Какой)-либо температу́рные отклоне́ния мо́гут привести́ к измене́нию фа́уны и фло́ры в э́том регио́не.","b":1},{"t":"para","text":"Dịch: Bất kỳ sự sai lệch nhiệt độ nào cũng có thể dẫn đến thay đổi hệ động thực vật..."},{"t":"para","text":"Giải thích: Văn phong khoa học → dùng -либо."},{"t":"para","text":"13. Вы мо́жете не беспоко́иться, в тру́дных ситуа́циях (кто)-нибудь (hoặc кто́-либо) всегда́ придёт к вам на по́мощь.","b":1},{"t":"para","text":"Dịch: Bạn không cần lo, trong tình huống khó khăn sẽ luôn có ai đó đến giúp."},{"t":"para","text":"Giải thích: Khẳng định chung → кто́-нибудь."},{"t":"para","text":"14. При возникнове́нии (какой)-либо осложне́ний больно́го на вертолёте перепра́вят в райо́нную больни́цу.","b":1},{"t":"para","text":"Dịch: Khi phát sinh bất kỳ biến chứng nào, bệnh nhân sẽ được trực thăng chuyển đến..."},{"t":"para","text":"Giải thích: Văn phong y tế/quy định → dùng -либо."},{"t":"para","text":"15. (Какой)-либо измене́ния в зако́н мо́гут быть внесены́ по́сле тща́тельных обсужде́ний.","b":1},{"t":"para","text":"Dịch: Bất cứ thay đổi nào trong luật cũng có thể được đưa vào sau khi thảo luận kỹ."},{"t":"para","text":"Giải thích: Văn phong pháp luật → dùng -либо."},{"t":"para","text":"16. Он обяза́тельно (что)-нибудь приду́мает, не беспоко́йтесь.","b":1},{"t":"para","text":"Dịch: Cậu ấy nhất định sẽ nghĩ ra cách gì đó/cái gì đó, đừng lo."},{"t":"para","text":"Giải thích: Văn nói, niềm tin vào tương lai → dùng -нибудь."}]},{"id":"06-s022","type":"exercise","title":"BÀI TẬP 498 (Trang 249)","num":498,"blocks":[{"t":"instruction","text":"Yêu cầu: Sử dụng đại từ/trạng từ với -то, -нибудь, -либо, кое- để đặt câu đáp lại các tình huống."},{"t":"para","text":"1. Tình huống: Bạn hỏi tại sao anh trai bạn đi. Bạn không biết lý do chính xác."},{"t":"para","text":"Đáp: — Я не зна́ю, он уе́хал по како́й-то причи́не. (Tôi không biết, anh ấy đi vì lý do nào đó)."},{"t":"para","text":"2. Tình huống: Bạn được hỏi gặp nhau ở đâu tiện. Hãy nói rằng ở trung tâm thành phố."},{"t":"para","text":"Đáp: — Дава́й встре́тимся где́-нибудь в це́нтре. (Hãy gặp nhau ở chỗ nào đó trong trung tâm đi - chưa chốt địa điểm cụ thể)."},{"t":"para","text":"3. Tình huống: Bạn hỏi xem người ta có biết kết quả bài kiểm tra không."},{"t":"para","text":"Đáp: — Тебе́ что́-нибудь (hoặc что́-либо) изве́стно о результа́тах контро́льной? (Cậu có biết gì về kết quả không?)."},{"t":"para","text":"4. Tình huống: Bạn được hỏi có giải quyết được bài toán này không. Hãy nói rằng bạn nhất định sẽ giải quyết bằng cách này hay cách khác."},{"t":"para","text":"Đáp: — Я ка́к-нибудь (hoặc та́к или ина́че) решу́ э́ту зада́чу. (Tớ sẽ giải bài này bằng cách nào đó)."},{"t":"para","text":"5. Tình huống: Mô tả ai đang ở trong phòng."},{"t":"para","text":"Đáp: — В ко́мнате нахо́дится кто́-то незнако́мый. (Trong phòng có ai đó lạ mặt)."},{"t":"para","text":"6. Tình huống: Nói rằng chỉ một người nghe nhạc, những người khác nghe khiêu vũ."},{"t":"example","text":"Đáp: — Му́зыку слу́шал то́лько оди́н, кто́-то друго́й танцева́л. (Hoặc: Кое-кто слушал, а другие...)."},{"t":"para","text":"7. Tình huống: Bạn hỏi người ta sẽ nói gì với tổng thống nếu được gặp."},{"t":"para","text":"Đáp: — Е́сли бы я встре́тил президе́нта, я бы спроси́л его́ о чём-нибудь ва́жном. (Tôi sẽ hỏi ông ấy về điều gì đó quan trọng)."},{"t":"para","text":"8. Tình huống: Bạn của bạn có nhận xét về bài làm của bạn."},{"t":"para","text":"Đáp: — У тебя́ есть каки́е-нибудь замеча́ния? (Cậu có nhận xét nào không?)."},{"t":"para","text":"9. Tình huống: Bạn muốn nói điều gì đó với bạn mình. (Thông tin cụ thể)."},{"t":"para","text":"Đáp: — Я хочу́ сообщи́ть тебе́ ко́е-что (hoặc не́что / что́-то) интере́сное. (Tớ muốn báo cho cậu cái này/chuyện này thú vị lắm)."},{"t":"para","text":"10. Tình huống: Đề nghị người qua đường chỉ đường."},{"t":"para","text":"Đáp: — Скажи́те, пожа́луйста, как пройти́...? Мо́жет быть, кто́-нибудь зна́ет доро́гу? (Có ai biết đường không?)."},{"t":"para","text":"11. Tình huống: Rừng cháy do bất cẩn với lửa."},{"t":"para","text":"Đáp: — Лес загоре́лся из-за чье́й-то небре́жности. (Rừng cháy do sự bất cẩn của ai đó)."},{"t":"para","text":"12. Tình huống: Bạn đến nhà bạn và gặp người lạ ở hành lang. Hỏi anh ta đi đâu."},{"t":"para","text":"Đáp: — Извини́те, вы к кому́-то идёте? (Xin lỗi, anh đang đi tìm ai đó à?)."}]},{"id":"06-s023","type":"exercise","title":"BÀI TẬP 499 (Trang 251 - Ôn tập Tiểu từ)","num":499,"blocks":[{"t":"instruction","text":"Yêu cầu: Chọn tiểu từ thích hợp trong ngoặc."},{"t":"para","text":"1. (ведь, то́лько, ра́зве) поклони́лся.","b":1},{"t":"para","text":"Chọn: то́лько (chỉ cúi chào)."},{"t":"example","text":"Dịch: Ông già lại không trả lời gì cả và chỉ cúi chào."},{"t":"para","text":"2. (про́сто, далеко́ не, едва́ не) са́мое лу́чшее ме́сто.","b":1},{"t":"para","text":"Chọn: далеко́ не (còn lâu mới là/chẳng phải là)."},{"t":"example","text":"Dịch: Tuy nhiên, khi nhận được tự do... cô ấy nhận được chẳng phải là chỗ tốt nhất trong căn hộ sang trọng đó."},{"t":"para","text":"3. (ещё, как раз, того́ и гляди́) о́чень мо́лоды.","b":1},{"t":"example","text":"Chọn: ещё (vẫn còn) hoặc ведь (nếu có trong ngoặc). Ở đây ещё hợp lý: vẫn còn rất trẻ."},{"t":"example","text":"Dịch: Cậu thấy đấy, Vanya: cả hai vẫn còn rất trẻ..."},{"t":"para","text":"4. (ведь, реши́тельно, про́сто) тала́нт.","b":1},{"t":"para","text":"Chọn: реши́тельно (quả quyết là/đúng là) hoặc про́сто (quả là). Cả 2 đều nhấn mạnh. Chọn про́сто (đơn giản là tài năng - cách nói tự nhiên)."},{"t":"example","text":"Dịch: ...anh ta không phải thiên tài, mà, quả là một tài năng."},{"t":"para","text":"5. (что ж, ведь, и́менно)","b":1},{"t":"para","text":"Chọn: и́менно (chính là)."},{"t":"example","text":"Dịch: Cặp mắt chính là đọc anh ta. (Ý nói đôi mắt thấu hiểu)."},{"t":"para","text":"6. (спеши́л на бал) ... (то́лько, пря́мо, едва́ не) поги́б.","b":1},{"t":"para","text":"Chọn: едва́ не (suýt nữa thì)."},{"t":"example","text":"Dịch: ...bay vào dây điện thoại và suýt nữa thì chết."},{"t":"para","text":"7. (лу́чше, пусть, ещё бы) подся́дьте.","b":1},{"t":"example","text":"Chọn: лу́чше (tốt hơn là) hoặc ну (nếu có). Trong ngữ cảnh khuyên bảo/mời mọc: \"Hay là bác ngồi lại gần đây đi\". Chọn лу́чше (Bác hãy/tốt hơn là ngồi lại gần đây)."},{"t":"para","text":"8. (ра́зве, то́лько бы, пря́мо) коси́ть.","b":1},{"t":"para","text":"Chọn: то́лько бы (giá mà/miễn là được)."},{"t":"example","text":"Dịch: Những ngày đẹp trời thế này, giá mà/chỉ muốn đi cắt cỏ."},{"t":"para","text":"9. (Ведь, Пусть, Ещё бы) есть, пра́во, э́такие лю́ди...","b":1},{"t":"para","text":"Chọn: Ведь (Quả tình là/Rõ ràng là)."},{"t":"example","text":"Dịch: Rõ ràng là có những người như thế..."},{"t":"para","text":"10. (того́ и жди, далеко́ не, едва́ не) утону́ли.","b":1},{"t":"para","text":"Chọn: едва́ не (suýt chút nữa thì)."},{"t":"example","text":"Dịch: Một lần chúng tôi suýt chút nữa chết đuối trong đầm lầy."},{"t":"para","text":"11. (Да, Пуска́й, Да́же) они́ живу́т как хотя́т.","b":1},{"t":"para","text":"Chọn: Пуска́й (Mặc kệ/Để cho)."},{"t":"example","text":"Dịch: Mặc kệ họ sống thế nào họ muốn."},{"t":"para","text":"12. (ра́зве, же, пря́мо) сканда́льным сеа́нсом.","b":1},{"t":"para","text":"Chọn: пря́мо (thực sự là/đúng là)."},{"t":"example","text":"Dịch: ...buổi biểu diễn hôm qua đúng là một buổi bê bối."},{"t":"para","text":"13. (ра́зве, же, пря́мо)","b":1},{"t":"para","text":"Chọn: ра́зве (chẳng lẽ)."},{"t":"example","text":"Dịch: ...ở cái nơi thế này chẳng lẽ lại không có ma quỷ sao."},{"t":"para","text":"14. (вро́де бы, того́ и жди, ведь)","b":1},{"t":"para","text":"Chọn: того́ и жди (trông chừng/coi bộ sắp)."},{"t":"example","text":"Dịch: ...lạnh toát sống lưng; coi bộ/khéo mà ma quỷ lại hiện ra lần nữa."},{"t":"para","text":"15. (э́так, да́же, лу́чше)","b":1},{"t":"para","text":"Chọn: да́же (thậm chí)."},{"t":"example","text":"Dịch: ...thậm chí cũng chỉ lơ mơ ngủ. (Ý nói ngủ không sâu)."},{"t":"para","text":"16. (лишь, да́же, пря́мо)","b":1},{"t":"para","text":"Chọn: лишь (chỉ)."},{"t":"example","text":"Dịch: Thời gian chỉ làm vỡ đá..."},{"t":"para","text":"17. (ра́зве то́лько, того́ и жди, как)","b":1},{"t":"para","text":"Chọn: ра́зве то́лько (hoạ chăng chỉ)."},{"t":"example","text":"Dịch: ...hoạ chăng chỉ khi bão tuyết mùa đông đập vỡ kính..."}]},{"id":"06-s024","type":"exercise","title":"BÀI TẬP 500 (Trang 252)","num":500,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền и́менно hoặc как ра́з."},{"t":"para","text":"1. ... ра́ннее у́тро.","b":1},{"t":"para","text":"Điền: И́менно (Chính là). Nhấn mạnh thời điểm xác định."},{"t":"example","text":"Dịch: Chính là sáng sớm..."},{"t":"para","text":"2. Меня́ така́я фо́рма не устра́ивает. — Что ... вас не устра́ивает?","b":1},{"t":"para","text":"Điền: и́менно (cụ thể là)."},{"t":"example","text":"Dịch: — Cái gì cụ thể làm ông không hài lòng?"},{"t":"para","text":"3. ... как изменя́лся.","b":1},{"t":"para","text":"Điền: и́менно (chính xác là như thế nào)."},{"t":"example","text":"Dịch: ...theo dõi xem chính xác nhân vật văn học đã thay đổi như thế nào..."},{"t":"para","text":"4. ... в то са́мое вре́мя.","b":1},{"t":"para","text":"Điền: И́менно (Chính vào)."},{"t":"example","text":"Dịch: Chính vào thời gian đó..."},{"t":"para","text":"5. ... в пере́дней зазвене́л телефо́н.","b":1},{"t":"para","text":"Điền: Как ра́з (Vừa đúng lúc đó/Vừa hay)."},{"t":"example","text":"Dịch: Vừa đúng lúc đó điện thoại ở tiền sảnh reo vang."},{"t":"para","text":"6. ... како́м-то оцепене́нии.","b":1},{"t":"example","text":"Điền: и́менно (cụ thể/chính xác). Hoặc в како́м-то (trong một trạng thái tê liệt nào đó - đã có sẵn каком-то thì không cần именно nữa, nhưng nếu phải điền thì и́менно nhấn mạnh trạng thái)."},{"t":"note","text":"Lưu ý: Ngữ cảnh này có thể là: \"tôi không biết chính xác là trạng thái gì\"."},{"t":"para","text":"7. Тут тата́рам меня́ уже́ битъ нельзя́, потому́ что я ... под уще́льем стал.","b":1},{"t":"para","text":"Điền: как ра́з (vừa đúng/vừa hay)."},{"t":"example","text":"Dịch: ...vì tôi vừa hay đứng ngay dưới hẻm núi."},{"t":"para","text":"8. Я не могу́ объесни́ть вам, что ... та́к; но мне почему́-то ка́жется...","b":1},{"t":"para","text":"Điền: и́менно (chính xác)."},{"t":"example","text":"Dịch: Tôi không thể giải thích cho anh chính xác là cái gì như thế; nhưng tôi cảm thấy..."},{"t":"para","text":"9. Начали́сь дра́ки... и всего́ бо́льше страда́л от э́той не́нависти го́род, кото́рый очути́лся ... посерёдке.","b":1},{"t":"para","text":"Điền: как ра́з (ngay đúng/vừa vặn)."},{"t":"example","text":"Dịch: ...thành phố mà vừa hay/lại nằm ngay chính giữa."},{"t":"para","text":"10. Что зна́чит ... родны́е.","b":1},{"t":"para","text":"Điền: и́менно (cụ thể/chính xác)."},{"t":"example","text":"Dịch: Thế nào chính xác/cụ thể là \"người thân\"?"},{"t":"para","text":"11. В э́тот моме́нт он ... отдыхáл.","b":1},{"t":"para","text":"Điền: как ра́з (đúng lúc đang/vừa hay đang)."},{"t":"example","text":"Dịch: Vào thời điểm đó ông ấy đúng là đang nghỉ ngơi..."},{"t":"para","text":"Tổng kết ngữ pháp:","b":1},{"t":"vocab","ru":"-то","vi":"Cụ thể, có thật (Specific).","g":null},{"t":"vocab","ru":"-нибудь","vi":"Bất định, bất kỳ (Any).","g":null},{"t":"vocab","ru":"кое-","vi":"Biết nhưng giấu (Certain/Some).","g":null},{"t":"vocab","ru":"именно","vi":"Chính xác là (Exactly/Namely).","g":null},{"t":"vocab","ru":"как раз","vi":"Vừa đúng, vừa hay (Just/Right).","g":null},{"t":"para","text":"Chào em, dưới đây là phần giải thích chi tiết, dịch thuật và hướng dẫn làm bài tập từ 501 đến 505 trong sách \"Грамматика русского языка в упражнениях и комментариях. Морфология\" (O. I. Glazunova), trang 253-257."},{"t":"para","text":"Phần này tập trung vào sự tinh tế trong việc sử dụng Tiểu từ (Частицы), Đại từ bất định (Неопределённые местоимения) và bắt đầu chuyển sang phần Động từ (Глагол) với các quy tắc biến đổi phụ âm quan trọng."}]},{"id":"06-s025","type":"exercise","title":"BÀI TẬP 501 (Trang 253)","num":501,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền tiểu từ ра́зве hoặc неуже́ли vào chỗ trống cho phù hợp ý nghĩa. Giải thích sự lựa chọn."},{"t":"para","text":"Ôn lại lý thuyết:","b":1},{"t":"vocab","ru":"Ра́зве (Chẳng lẽ... ư/à?)","vi":"Dùng khi người nói nghi ngờ, muốn hỏi lại để xác nhận một thông tin mà mình nghĩ ngược lại (thường mang sắc thái nhẹ nhàng hơn, \"Tôi tưởng là..., sao lại...?\").","g":null},{"t":"vocab","ru":"Неуже́ли (Thật ư...? / Chẳng lẽ lại...?)","vi":"Dùng khi người nói vô cùng ngạc nhiên, sửng sốt, không thể tin được vào điều mình nghe thấy hoặc nhìn thấy (sắc thái cảm xúc mạnh).","g":null},{"t":"para","text":"1. — Почему́ же вы се́рдитесь? Ра́зве я сказа́л вам что-нибу́дь неприя́тное?","b":1},{"t":"para","text":"Dịch: — Tại sao ông lại giận? Chẳng lẽ tôi đã nói điều gì khó nghe với ông sao?"},{"t":"example","text":"Giải thích: Người nói tin rằng mình không nói gì xấu, nên dùng Ра́зве để hỏi lại với sự nghi hoặc (Tôi tưởng tôi không nói gì xấu chứ?)."},{"t":"para","text":"2. \"Кто ж э́то обе́дал? — поду́мал геро́й наш. — Неуже́ли я? А всё мо́жет быть! Пообе́дал, да так и не заме́тил себе́; как же мне быть?\"","b":1},{"t":"para","text":"Dịch: \"Ai đã ăn trưa nhỉ? — nhân vật của chúng ta suy nghĩ. — Chẳng lẽ là/Thật sự là tôi ư? Mà cũng có thể lắm! Ăn rồi mà chính mình cũng chẳng để ý; tôi biết làm sao đây?\""},{"t":"example","text":"Giải thích: Nhân vật quá ngạc nhiên và không tin nổi vào hành động của chính mình (ăn rồi mà không nhớ), biểu thị sự sửng sốt cao độ → Неуже́ли."},{"t":"para","text":"3. Открыва́ю страни́цу... неуже́ли э́то спал? — сказа́л про себя́ Лёвко...","b":1},{"t":"para","text":"Dịch: Mở trang sách ra... thật ư, là mình đã ngủ sao? — Lyevko tự nhủ..."},{"t":"example","text":"Giải thích: Ngạc nhiên vì sự việc đã xảy ra (ngủ quên) mà không biết → Неуже́ли."},{"t":"para","text":"4. Так жи́во, как бу́дто наяву́! Чуднó, чуднó! Неуже́ли ты меня́ погуби́ла?","b":1},{"t":"para","text":"Dịch: Sống động y như thật vậy! Kỳ lạ, kỳ lạ quá! Chẳng lẽ/Có thật là em đã hại anh sao?"},{"t":"example","text":"Giải thích: Cảm xúc bàng hoàng, không muốn tin vào sự thật đau lòng → Неуже́ли."},{"t":"para","text":"5. — Я ду́маю, — сказа́л я, — что нам лу́чше всего́ расста́ться. — Ра́зве ты не слы́шишь?","b":1},{"t":"para","text":"Dịch: — Anh nghĩ, — tôi nói, — tốt nhất là chúng ta nên chia tay. — Chẳng lẽ em không nghe thấy à?"},{"t":"example","text":"Giải thích: Người nói nghĩ rằng người nghe phải nghe thấy rồi, hỏi lại để xác nhận sự chú ý → Ра́зве."},{"t":"para","text":"6. Уже́ вы́йдя на у́лицу, Кречма́р почему́-то посмотре́л на часы́. Бы́ло за по́лночь. Неуже́ли он пробы́л там пять часо́в?","b":1},{"t":"para","text":"Dịch: Khi đã bước ra đường, Krechmar chẳng hiểu sao lại nhìn đồng hồ. Đã quá nửa đêm. Thật ư, anh ta đã ở đó tận 5 tiếng đồng hồ sao?"},{"t":"example","text":"Giải thích: Sửng sốt về thời gian trôi qua quá nhanh, khó tin là đã 5 tiếng → Неуже́ли."},{"t":"para","text":"7. Мы тепе́рь совсе́м не мо́жем знать, что, со́бственно, бу́дет счита́ться высо́ким, ва́жным и что жа́лким, смешны́м. Ра́зве откры́тие Копе́рника и́ли, поло́жим, Колу́мба не каза́лось в пе́рвое вре́мя нену́жным, смешны́м... ра́зве не каза́лся и́стиной? (Lưu ý: Câu gốc trong văn học khá dài và phức tạp, ý chính là so sánh sự thay đổi quan điểm)."},{"t":"para","text":"Dịch: Giờ đây chúng ta hoàn toàn không thể biết cái gì thực chất sẽ được coi là cao cả, quan trọng và cái gì là thảm hại, nực cười. Chẳng lẽ phát kiến của Copernicus hay, giả dụ, của Columbus, trong thời gian đầu đã không từng có vẻ vô dụng, nực cười sao...?"},{"t":"example","text":"Giải thích: Dùng Ра́зве trong câu hỏi tu từ để khẳng định ngược lại (Rõ ràng là nó đã từng bị coi là nực cười)."},{"t":"para","text":"8. — Ната́лья Алексе́евна, вы ухо́дите? Неуже́ли мы так расста́немся?","b":1},{"t":"para","text":"Dịch: — Natalia Alekseevna, cô đi sao? Chẳng lẽ/Thật sự là chúng ta sẽ chia tay như thế này ư?"},{"t":"example","text":"Giải thích: Biểu thị sự thất vọng, không muốn tin vào kết cục chia tay → Неуже́ли."}]},{"id":"06-s026","type":"exercise","title":"BÀI TẬP 502 (Trang 253)","num":502,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền đại từ/trạng từ thích hợp với -то, -нибудь, кое- vào chỗ trống."},{"t":"subhead","text":"Quy tắc:","b":1},{"t":"vocab","ru":"-то","vi":"Cụ thể, đã xảy ra, người nói biết nhưng không nhớ rõ hoặc người nói hình dung ra đối tượng cụ thể.","g":null},{"t":"vocab","ru":"-нибудь","vi":"Bất định, dùng trong câu hỏi, tương lai, mệnh lệnh, \"bất kỳ cái nào\".","g":null},{"t":"vocab","ru":"кое-","vi":"Người nói biết rõ nhưng không muốn nói ra hoặc giấu diếm.","g":null},{"t":"para","text":"a) 1. Я, призна́юсь, сомнева́юсь, что́бы моя́ бесе́да могла́ доста́вить вам (какое) како́е-нибудь удово́льствие.","b":1},{"t":"para","text":"Dịch: Tôi thú thật là tôi nghi ngờ việc cuộc trò chuyện của tôi có thể mang lại cho ông bất kỳ niềm vui nào."},{"t":"example","text":"Giải thích: Trong câu phủ định/nghi ngờ, ý chỉ \"bất cứ cái gì\" → -нибудь."},{"t":"para","text":"2. ..., в ца́рские времена́, меблиро́вка прису́тственных мест производи́лась по трафаре́ту. (Когда) Когда́-то...","b":1},{"t":"para","text":"Dịch: Hồi xưa/Trước kia, vào thời Sa hoàng, việc trang trí nội thất công sở được làm theo khuôn mẫu."},{"t":"example","text":"Giải thích: Chỉ một thời điểm trong quá khứ xa xôi (đã xảy ra) → когда́-то."},{"t":"para","text":"3. Сего́дня днём весь бе́рег был по́лон (какие) каки́ми-то безде́льниками и стару́хами.","b":1},{"t":"para","text":"Dịch: Trưa nay cả bờ biển đầy rẫy những kẻ rỗi hơi và mấy bà già nào đó."},{"t":"example","text":"Giải thích: Sự việc thực tế đã nhìn thấy, những người cụ thể nhưng không xác định danh tính → -то."},{"t":"para","text":"4. Уже́ в эмигра́ции (какие) ко́е-каки́ми заня́тными све́дениями снабди́л меня́ двою́родный мой дя́дюшка.","b":1},{"t":"para","text":"Dịch: Khi đã di cư, ông chú họ đã cung cấp cho tôi một vài thông tin thú vị (cụ thể mà tôi biết)."},{"t":"example","text":"Giải thích: Người nói biết rõ thông tin đó là gì (được nhắc đến như một nguồn tin bí mật/riêng tư) → кое-. (Dùng какими-то cũng chấp nhận được nếu người nói không nhớ rõ, nhưng кое- hay hơn trong ngữ cảnh \"thông tin\")."},{"t":"para","text":"5. — Каки́е, одна́ко, у вас дороги́е да́чи, — мо́рщится инжене́р. — Всё в четы́реста да в три́ста рубле́й. Ужа́сно! Вы покажи́те нам (что) чтó-нибудь подеше́вле.","b":1},{"t":"para","text":"Dịch: — Chà, nhà nghỉ của các bác đắt quá, — kỹ sư nhăn mặt. — Toàn 400 với 300 rúp. Kinh khủng! Bác hãy chỉ cho chúng tôi cái gì đó rẻ hơn đi (bất cứ cái nào cũng được)."},{"t":"example","text":"Giải thích: Yêu cầu tìm một đối tượng chưa xác định → -нибудь."},{"t":"para","text":"6. ..., то́чно острова́, лежа́ли на ней гряды́ облако́в, (где) где́-то...","b":1},{"t":"para","text":"Dịch: ...như những hòn đảo, những dải mây nằm trên đó, ở đâu đó (xa xa)..."},{"t":"example","text":"Giải thích: Chỉ địa điểm không xác định rõ ràng về vị trí chính xác nhưng có tồn tại → -то."},{"t":"para","text":"7. И он поле́з в боково́й карма́н, отку́да действи́тельно вы́нул мно́жество лежа́лых бума́жек, но показа́л их не бра́ту, а председа́телю исполко́ма, да и то и́здали (кто) кому́-то (hoặc кое-кому).","b":1},{"t":"para","text":"Dịch: Và hắn thò tay vào túi áo, lôi ra một đống giấy tờ cũ nát, nhưng không đưa cho anh trai xem, mà đưa cho chủ tịch ủy ban, mà cũng chỉ đưa cho người nào đó xem từ xa thôi."},{"t":"example","text":"Giải thích: Hắn đưa cho một người cụ thể (chủ tịch hoặc ai đó ở đó) -> кому-то."},{"t":"para","text":"8. Вдруг среди́ ночно́й тишины́ раздаю́тся (чьи) чьи́-то шаги́ и звя́канье шпор.","b":1},{"t":"para","text":"Dịch: Bỗng nhiên giữa màn đêm yên tĩnh vang lên tiếng bước chân của ai đó và tiếng cựa sắt loảng xoảng."},{"t":"example","text":"Giải thích: Tiếng động có thật, của một người cụ thể nhưng chưa biết là ai → -то."},{"t":"para","text":"9. Давно́ уже́ име́л я наме́рение написа́ть исто́рию (какой) како́го-то (hoặc како́го-нибудь) го́рода (и́ли кра́я) в да́нный пери́од вре́мени...","b":1},{"t":"para","text":"Dịch: Từ lâu tôi đã có ý định viết lịch sử của một thành phố (hay vùng đất) nào đó trong giai đoạn này..."},{"t":"example","text":"Giải thích: Nếu tác giả nói về một thành phố giả định chung chung → како́го-нибудь. Nếu tác giả ám chỉ một thành phố cụ thể nhưng giấu tên (như trong văn học) → како́го-то. Trong ngữ cảnh văn học cổ điển (như Gogol hay Saltykov-Shchedrin), thường dùng како́го-то để tạo sự bí ẩn châm biếm."}]}]};
